{
  "name": "SkyCast AI - Hyperlocal Weather",
  "description": "A modern, dynamic weather application featuring hyperlocal forecasts, interactive radar simulation, severe weather alerts, and AI-powered weather insights using Gemini.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface WeatherLocation {
  city: string;
  district: string;
  lat: number;
  lng: number;
}

export interface HourlyForecast {
  time: string; // HH:00
  temp: number;
  precipChance: number;
  condition: 'Sunny' | 'Cloudy' | 'Rain' | 'Storm' | 'Partly Cloudy';
}

export interface DailyForecast {
  day: string;
  minTemp: number;
  maxTemp: number;
  condition: 'Sunny' | 'Cloudy' | 'Rain' | 'Storm' | 'Partly Cloudy';
}

export interface Alert {
  id: string;
  severity: 'moderate' | 'severe' | 'extreme';
  title: string;
  description: string;
  issuedAt: string;
}

export interface CurrentWeather {
  temp: number;
  feelsLike: number;
  humidity: number;
  windSpeed: number;
  uvIndex: number;
  condition: 'Sunny' | 'Cloudy' | 'Rain' | 'Storm' | 'Partly Cloudy';
  description: string;
  aqi: number; // Air Quality Index
}

export interface WeatherData {
  location: WeatherLocation;
  current: CurrentWeather;
  hourly: HourlyForecast[];
  daily: DailyForecast[];
  alerts: Alert[];
}

export enum AppState {
  ONBOARDING,
  LOADING,
  DASHBOARD,
  ERROR
}

import { WeatherData, HourlyForecast, DailyForecast, Alert } from './types';

// Helper to generate mock weather data since we don't have a real weather API key
// In a production app, this would be replaced by calls to OpenWeatherMap or Tomorrow.io
export const generateMockWeather = (city: string): WeatherData => {
  const conditions = ['Sunny', 'Cloudy', 'Rain', 'Partly Cloudy', 'Storm'] as const;

  const currentCondition = conditions[Math.floor(Math.random() * conditions.length)];
  const baseTemp = 20 + Math.random() * 10; // 20-30 degrees C

  const hourly: HourlyForecast[] = Array.from({ length: 24 }).map((_, i) => {
    const hour = (new Date().getHours() + i) % 24;
    return {
      time: `${hour.toString().padStart(2, '0')}:00`,
      temp: Math.round(baseTemp + Math.sin(i / 3) * 5),
      precipChance: Math.floor(Math.random() * 30),
      condition: conditions[Math.floor(Math.random() * conditions.length)],
    };
  });

  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const daily: DailyForecast[] = Array.from({ length: 7 }).map((_, i) => {
    const date = new Date();
    date.setDate(date.getDate() + i);
    return {
      day: days[date.getDay()],
      minTemp: Math.round(baseTemp - 5 - Math.random() * 3),
      maxTemp: Math.round(baseTemp + 5 + Math.random() * 3),
      condition: conditions[Math.floor(Math.random() * conditions.length)],
    };
  });

  const alerts: Alert[] = [];
  if (Math.random() > 0.7) {
    alerts.push({
      id: 'alert-1',
      severity: 'severe',
      title: 'Severe Thunderstorm Warning',
      description: 'Strong winds and heavy rain expected in your area until 6:00 PM.',
      issuedAt: '10:00 AM'
    });
  }

  return {
    location: {
      city: city || 'Lisbon',
      district: 'Downtown',
      lat: 38.7223,
      lng: -9.1393
    },
    current: {
      temp: Math.round(baseTemp),
      feelsLike: Math.round(baseTemp + 2),
      humidity: 45 + Math.floor(Math.random() * 20),
      windSpeed: 12 + Math.floor(Math.random() * 10),
      uvIndex: Math.floor(Math.random() * 10),
      condition: currentCondition,
      description: currentCondition === 'Sunny' ? 'Clear sky' : 'Overcast clouds',
      aqi: 35
    },
    hourly,
    daily,
    alerts
  };
};

export const DEFAULT_CITIES = [
  'São Paulo', 'Rio de Janeiro', 'Lisbon', 'New York', 'Tokyo', 'London'
];

import { GoogleGenAI } from "@google/genai";
import { WeatherData } from '../types';

let genAI: GoogleGenAI | null = null;

const getAIClient = () => {
  if (!genAI) {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      console.error("API_KEY is missing in environment variables.");
      return null;
    }
    genAI = new GoogleGenAI({ apiKey });
  }
  return genAI;
};

export const generateWeatherInsight = async (data: WeatherData): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return "AI services unavailable.";

  const prompt = `
    You are a witty, helpful personal weather assistant app named "SkyCast".
    The current weather data for ${data.location.city} is:
    - Condition: ${data.current.condition}
    - Temp: ${data.current.temp}°C (Feels like ${data.current.feelsLike}°C)
    - Humidity: ${data.current.humidity}%
    - Wind: ${data.current.windSpeed} km/h
    - UV Index: ${data.current.uvIndex}
    - Alerts: ${data.alerts.length > 0 ? data.alerts[0].title : "None"}

    Provide a short, 2-sentence insight. 
    1st sentence: Summary of the vibe.
    2nd sentence: Recommendation (clothing, activity, or safety).
    Keep it modern and slightly fun.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Unable to generate insight right now.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Local weather data loaded. AI insight unavailable.";
  }
};

import React from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { HourlyForecast } from '../types';

interface ForecastChartProps {
  data: HourlyForecast[];
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-slate-800 border border-slate-700 p-2 rounded-lg shadow-xl">
        <p className="text-slate-200 text-sm font-medium">{label}</p>
        <p className="text-sky-400 text-lg font-bold">
          {payload[0].value}°C
        </p>
        <p className="text-slate-400 text-xs">
          {payload[0].payload.condition}
        </p>
      </div>
    );
  }
  return null;
};

const ForecastChart: React.FC<ForecastChartProps> = ({ data }) => {
  // Take next 12 hours for cleaner mobile view
  const chartData = data.slice(0, 12);

  return (
    <div className="h-64 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart
          data={chartData}
          margin={{
            top: 10,
            right: 10,
            left: -20,
            bottom: 0,
          }}
        >
          <defs>
            <linearGradient id="colorTemp" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#38bdf8" stopOpacity={0.8}/>
              <stop offset="95%" stopColor="#38bdf8" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
          <XAxis 
            dataKey="time" 
            stroke="#94a3b8" 
            fontSize={12} 
            tickLine={false}
            axisLine={false}
          />
          <YAxis 
            stroke="#94a3b8" 
            fontSize={12} 
            tickLine={false}
            axisLine={false}
            domain={['dataMin - 5', 'dataMax + 5']}
          />
          <Tooltip content={<CustomTooltip />} />
          <Area 
            type="monotone" 
            dataKey="temp" 
            stroke="#38bdf8" 
            strokeWidth={3}
            fillOpacity={1} 
            fill="url(#colorTemp)" 
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export default ForecastChart;

import React, { useEffect, useState } from 'react';

