  useEffect(() => {
    const interval = setInterval(() => {
      setRotation(r => (r + 2) % 360);
    }, 20);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="relative w-full h-64 bg-slate-900 rounded-xl overflow-hidden border border-slate-700 shadow-inner">
      {/* Map Background (Simulated) */}
      <div className="absolute inset-0 opacity-30">
        <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg">
          <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse">
            <path d="M 40 0 L 0 0 0 40" fill="none" stroke="#475569" strokeWidth="0.5"/>
          </pattern>
          <rect width="100%" height="100%" fill="url(#grid)" />
          {/* Simulated landmasses */}
          <path d="M 50 150 Q 100 100 150 150 T 250 150" stroke="#64748b" strokeWidth="2" fill="none" />
          <path d="M 10 50 Q 60 80 80 30" stroke="#64748b" strokeWidth="2" fill="none" />
          <circle cx="200" cy="100" r="4" fill="#ef4444" className="animate-pulse" /> {/* Location dot */}
        </svg>
      </div>

      {/* Radar Sweep */}
      <div 
        className="absolute inset-0 flex items-center justify-center pointer-events-none"
      >
        <div 
          className="w-[200%] h-[200%] bg-gradient-to-r from-transparent via-emerald-500/20 to-transparent"
          style={{ 
            transform: `rotate(${rotation}deg)`,
            transformOrigin: 'center center',
            maskImage: 'radial-gradient(circle, black 0%, transparent 70%)',
            WebkitMaskImage: 'radial-gradient(circle, black 0%, transparent 70%)'
          }}
        />
      </div>

      {/* Radar Rings */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <div className="w-32 h-32 border border-slate-600/50 rounded-full"></div>
        <div className="w-64 h-64 border border-slate-600/50 rounded-full absolute"></div>
        <div className="w-96 h-96 border border-slate-600/50 rounded-full absolute"></div>
      </div>

      {/* Rain blobs (Simulated) */}
      <div className="absolute top-1/4 left-1/4 w-16 h-16 bg-blue-500/30 blur-xl rounded-full animate-pulse"></div>
      <div className="absolute bottom-1/3 right-1/4 w-24 h-24 bg-blue-600/40 blur-xl rounded-full"></div>

      <div className="absolute bottom-4 right-4 bg-slate-900/80 backdrop-blur px-3 py-1 rounded text-xs text-slate-300 border border-slate-700">
        Live Radar
      </div>
    </div>
  );
};

export default RadarView;

import React from 'react';
import { WeatherData } from '../types';
import { Wind, Droplets, Sun, CloudRain, Cloud, CloudLightning, Thermometer } from 'lucide-react';

interface Props {
  data: WeatherData;
}

const ConditionIcon = ({ condition }: { condition: string }) => {
  switch (condition) {
    case 'Sunny': return <Sun className="w-16 h-16 text-amber-400" />;
    case 'Rain': return <CloudRain className="w-16 h-16 text-blue-400" />;
    case 'Storm': return <CloudLightning className="w-16 h-16 text-purple-400" />;
    case 'Partly Cloudy': return <Cloud className="w-16 h-16 text-slate-300" />;
    default: return <Cloud className="w-16 h-16 text-slate-400" />;
  }
};

const CurrentConditions: React.FC<Props> = ({ data }) => {
  const { current } = data;

  return (
    <div className="relative bg-gradient-to-br from-slate-800 to-slate-900 rounded-3xl p-6 md:p-8 text-white shadow-2xl overflow-hidden border border-slate-700/50">
      {/* Decorative background glow */}
      <div className="absolute -top-24 -right-24 w-64 h-64 bg-sky-500/20 blur-3xl rounded-full pointer-events-none"></div>

      <div className="flex flex-col md:flex-row justify-between items-center z-10 relative">
        <div className="text-center md:text-left">
          <h2 className="text-sm font-medium text-slate-400 uppercase tracking-wider mb-1">
            {data.location.district}
          </h2>
          <h1 className="text-3xl md:text-4xl font-bold mb-4">{data.location.city}</h1>

          <div className="flex items-center justify-center md:justify-start space-x-4 mb-4">
            <ConditionIcon condition={current.condition} />
            <div className="text-7xl font-bold tracking-tighter">
              {current.temp}°
            </div>
          </div>
          <p className="text-lg text-slate-300 font-medium">{current.description}</p>
          <p className="text-sm text-slate-400">Feels like {current.feelsLike}°</p>
        </div>

        <div className="grid grid-cols-2 gap-4 mt-8 md:mt-0 w-full md:w-auto">
          <div className="bg-slate-700/30 p-4 rounded-xl backdrop-blur-sm border border-slate-600/30 flex flex-col items-center">
            <Wind className="w-6 h-6 text-sky-300 mb-2" />
            <span className="text-xs text-slate-400">Wind</span>
            <span className="text-lg font-semibold">{current.windSpeed} km/h</span>
          </div>
          <div className="bg-slate-700/30 p-4 rounded-xl backdrop-blur-sm border border-slate-600/30 flex flex-col items-center">
            <Droplets className="w-6 h-6 text-sky-300 mb-2" />
            <span className="text-xs text-slate-400">Humidity</span>
            <span className="text-lg font-semibold">{current.humidity}%</span>
          </div>
           <div className="bg-slate-700/30 p-4 rounded-xl backdrop-blur-sm border border-slate-600/30 flex flex-col items-center">
            <Sun className="w-6 h-6 text-sky-300 mb-2" />
            <span className="text-xs text-slate-400">UV Index</span>
            <span className="text-lg font-semibold">{current.uvIndex}</span>
          </div>
           <div className="bg-slate-700/30 p-4 rounded-xl backdrop-blur-sm border border-slate-600/30 flex flex-col items-center">
            <Thermometer className="w-6 h-6 text-sky-300 mb-2" />
            <span className="text-xs text-slate-400">AQI</span>
            <span className="text-lg font-semibold">{current.aqi}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CurrentConditions;

import React, { useEffect, useState } from 'react';
import { Sparkles, RefreshCw } from 'lucide-react';
import { generateWeatherInsight } from '../services/geminiService';
import { WeatherData } from '../types';

interface Props {
  weatherData: WeatherData;
}

const AIWeatherInsight: React.FC<Props> = ({ weatherData }) => {
  const [insight, setInsight] = useState<string>("");
  const [loading, setLoading] = useState<boolean>(false);

  const fetchInsight = async () => {
    setLoading(true);
    const result = await generateWeatherInsight(weatherData);
    setInsight(result);
    setLoading(false);
  };

  useEffect(() => {
    fetchInsight();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [weatherData.location.city]); // Re-fetch only when city changes

  return (
    <div className="bg-gradient-to-r from-indigo-900/50 to-purple-900/50 border border-indigo-500/30 p-4 rounded-2xl relative overflow-hidden group">
      <div className="flex justify-between items-start mb-2">
        <div className="flex items-center space-x-2">
          <div className="bg-indigo-500 p-1.5 rounded-lg shadow-lg shadow-indigo-500/20">
            <Sparkles className="w-4 h-4 text-white" />
          </div>
          <h3 className="text-indigo-200 font-semibold text-sm tracking-wide">SkyCast AI Insight</h3>
        </div>
        <button 
          onClick={fetchInsight}
          disabled={loading}
          className="text-indigo-300 hover:text-white transition-colors p-1"
        >
          <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      <div className="min-h-[3rem]">
        {loading ? (
          <div className="space-y-2 animate-pulse">
            <div className="h-4 bg-indigo-500/20 rounded w-3/4"></div>
            <div className="h-4 bg-indigo-500/20 rounded w-1/2"></div>
          </div>
        ) : (
          <p className="text-slate-200 text-sm leading-relaxed font-light">
            {insight}
          </p>
        )}
      </div>
    </div>
  );
};

export default AIWeatherInsight;

import React, { useState, useEffect } from 'react';
import { MapPin, Navigation, Bell, Settings, Menu, ShieldAlert } from 'lucide-react';
import { WeatherData, AppState } from './types';
import { generateMockWeather, DEFAULT_CITIES } from './constants';
import CurrentConditions from './components/CurrentConditions';
import ForecastChart from './components/ForecastChart';
import RadarView from './components/RadarView';
import AIWeatherInsight from './components/AIWeatherInsight';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [weatherData, setWeatherData] = useState<WeatherData | null>(null);
  const [locationPermission, setLocationPermission] = useState<boolean>(false);
  const [showMobileMenu, setShowMobileMenu] = useState(false);

  const handleGrantLocation = () => {
    // Simulate location permission grant
    setLocationPermission(true);
    setAppState(AppState.LOADING);

    setTimeout(() => {
      // Simulate fetching data for "Current Location" (Mocked as Lisbon for demo)
      const data = generateMockWeather('Lisbon');
      setWeatherData(data);
      setAppState(AppState.DASHBOARD);
    }, 1500);
  };

  const handleCityChange = (city: string) => {
    setAppState(AppState.LOADING);
    setShowMobileMenu(false);
    setTimeout(() => {
      const data = generateMockWeather(city);
      setWeatherData(data);
      setAppState(AppState.DASHBOARD);
    }, 800);
  };

  if (appState === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 p-6 text-center">
        <div className="w-24 h-24 bg-sky-500 rounded-full flex items-center justify-center mb-8 shadow-2xl shadow-sky-500/20 animate-bounce">
          <Navigation className="w-12 h-12 text-white" />
        </div>
        <h1 className="text-4xl font-bold text-white mb-4">SkyCast AI</h1>
        <p className="text-slate-400 max-w-sm mb-8">
          Hyperlocal forecasts, AI-powered insights, and real-time severe weather alerts. 
          Enable location to get started.
        </p>
        <button
          onClick={handleGrantLocation}
          className="bg-sky-500 hover:bg-sky-400 text-white px-8 py-4 rounded-2xl font-semibold text-lg transition-all shadow-lg hover:shadow-sky-500/30 flex items-center gap-2"
        >
          <MapPin className="w-5 h-5" />
          Enable Location
        </button>
        <p className="mt-8 text-xs text-slate-600">
          We prioritize your privacy. Location data is only used locally for forecasts.
        </p>
      </div>
    );
  }

  if (appState === AppState.LOADING || !weatherData) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <div className="flex flex-col items-center">
          <div className="w-12 h-12 border-4 border-sky-500 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-slate-400 animate-pulse">Forecasting...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 text-slate-50 pb-20 md:pb-0">

      {/* Top Navigation */}
      <header className="fixed top-0 w-full bg-slate-900/80 backdrop-blur-md border-b border-slate-800 z-50 px-4 py-3 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-sky-500 rounded-lg flex items-center justify-center">
             <Navigation className="w-5 h-5 text-white" />
          </div>
          <span className="font-bold text-lg hidden md:block">SkyCast AI</span>
        </div>

        <div className="flex items-center gap-4">
           {/* Location Selector (Simple Dropdown) */}
           <select 
              className="bg-slate-800 border border-slate-700 text-sm rounded-lg p-2 outline-none focus:border-sky-500"
              value={weatherData.location.city}
              onChange={(e) => handleCityChange(e.target.value)}
            >
              {DEFAULT_CITIES.map(city => (
                <option key={city} value={city}>{city}</option>
              ))}
            </select>

            <button className="p-2 hover:bg-slate-800 rounded-full relative">
              <Bell className="w-5 h-5 text-slate-400" />
              {weatherData.alerts.length > 0 && (
                <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full"></span>
              )}
            </button>
            <button 
              className="md:hidden p-2 hover:bg-slate-800 rounded-full"
              onClick={() => setShowMobileMenu(!showMobileMenu)}
            >
              <Menu className="w-5 h-5 text-slate-400" />
            </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 pt-20 max-w-5xl">

        {/* Severe Weather Alert Banner */}
        {weatherData.alerts.map(alert => (
          <div key={alert.id} className="mb-6 bg-red-500/10 border border-red-500/50 rounded-xl p-4 flex items-start gap-4 animate-pulse">
            <ShieldAlert className="w-6 h-6 text-red-500 shrink-0 mt-1" />
            <div>
              <h3 className="font-bold text-red-400">{alert.title}</h3>
              <p className="text-sm text-red-200/80">{alert.description}</p>
              <p className="text-xs text-red-300 mt-1">Issued: {alert.issuedAt}</p>
            </div>
          </div>
        ))}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

          {/* Left Column: Main Info */}
          <div className="md:col-span-2 space-y-6">
            <CurrentConditions data={weatherData} />

            <div className="bg-slate-800/50 border border-slate-700/50 rounded-2xl p-6">
              <div className="flex justify-between items-center mb-6">
                <h3 className="font-semibold text-slate-200">Hourly Forecast</h3>
                <span className="text-xs text-slate-500">Next 12 Hours</span>
              </div>
              <ForecastChart data={weatherData.hourly} />
            </div>

             <div className="bg-slate-800/50 border border-slate-700/50 rounded-2xl p-6">
              <h3 className="font-semibold text-slate-200 mb-4">Interactive Radar</h3>
              <RadarView />
            </div>
          </div>

          {/* Right Column: AI & Details */}
          <div className="space-y-6">
            <AIWeatherInsight weatherData={weatherData} />

            <div className="bg-slate-800/50 border border-slate-700/50 rounded-2xl p-6">
              <h3 className="font-semibold text-slate-200 mb-4">7-Day Forecast</h3>
              <div className="space-y-4">
                {weatherData.daily.map((day, idx) => (
                  <div key={idx} className="flex items-center justify-between text-sm group hover:bg-slate-700/30 p-2 rounded transition-colors">
                    <span className="w-12 text-slate-400 font-medium">{day.day}</span>
                    <div className="flex-1 px-4">
                       <div className="h-1.5 w-full bg-slate-700 rounded-full overflow-hidden">
                          <div 
                            className="h-full bg-gradient-to-r from-sky-500 to-amber-400"
                            style={{ 
                              width: `${(day.maxTemp - day.minTemp) * 5}%`,
                              marginLeft: `${(day.minTemp) * 2}%` 
                            }}
                          ></div>
                       </div>
                    </div>
                    <div className="flex gap-3 text-slate-300 w-20 justify-end font-mono">
                      <span className="opacity-60">{day.minTemp}°</span>
                      <span className="font-bold">{day.maxTemp}°</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Customization / Widgets Teaser */}
            <div className="bg-slate-800/50 border border-slate-700/50 rounded-2xl p-6">
              <div className="flex items-center gap-2 mb-2">
                 <Settings className="w-4 h-4 text-slate-400" />
                 <h3 className="font-semibold text-slate-200">Customization</h3>
