import { WeatherData, HourlyForecast, DailyForecast, Alert } from './types';

// Helper to generate mock weather data since we don't have a real weather API key
// In a production app, this would be replaced by calls to OpenWeatherMap or Tomorrow.io
export const generateMockWeather = (city: string, lat?: number, lng?: number): WeatherData => {
  const conditions = ['Sunny', 'Cloudy', 'Rain', 'Partly Cloudy', 'Storm'] as const;

  const currentCondition = conditions[Math.floor(Math.random() * conditions.length)];
  const baseTemp = 20 + Math.random() * 10; // 20-30 degrees C

  const hourly: HourlyForecast[] = Array.from({ length: 24 }).map((_, i) => {
    const hour = (new Date().getHours() + i) % 24;
    return {
      time: `${hour.toString().padStart(2, '0')}:00`,
      temp: Math.round(baseTemp + Math.sin(i / 3) * 5),
      precipChance: Math.floor(Math.random() * 30),
      condition: conditions[Math.floor(Math.random() * conditions.length)],
    };
  });

  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const daily: DailyForecast[] = Array.from({ length: 7 }).map((_, i) => {
    const date = new Date();
    date.setDate(date.getDate() + i);
    return {
      day: days[date.getDay()],
      minTemp: Math.round(baseTemp - 5 - Math.random() * 3),
      maxTemp: Math.round(baseTemp + 5 + Math.random() * 3),
      condition: conditions[Math.floor(Math.random() * conditions.length)],
    };
  });

  const alerts: Alert[] = [];
  if (Math.random() > 0.8) {
    alerts.push({
      id: 'alert-1',
      severity: 'severe',
      title: 'Severe Thunderstorm Warning',
      description: 'Strong winds and heavy rain expected in your area until 6:00 PM.',
      issuedAt: '10:00 AM'
    });
  }

  // Use provided coordinates or default to Lisbon
  const finalLat = lat || 38.7223;
  const finalLng = lng || -9.1393;
  const districtName = city === 'Current Location' ? 
    `Lat: ${finalLat.toFixed(2)}, Lng: ${finalLng.toFixed(2)}` : 
    'Downtown';

  return {
    location: {
      city: city,
      district: districtName,
      lat: finalLat,
      lng: finalLng
    },
    current: {
      temp: Math.round(baseTemp),
      feelsLike: Math.round(baseTemp + 2),
      humidity: 45 + Math.floor(Math.random() * 20),
      windSpeed: 12 + Math.floor(Math.random() * 10),
      uvIndex: Math.floor(Math.random() * 10),
      condition: currentCondition,
      description: currentCondition === 'Sunny' ? 'Clear sky' : 'Overcast clouds',
      aqi: 35
    },
    hourly,
    daily,
    alerts
  };
};

export const DEFAULT_CITIES = [
  'São Paulo', 'Rio de Janeiro', 'Lisbon', 'New York', 'Tokyo', 'London'
];

import { GoogleGenAI } from "@google/genai";
import { WeatherData } from '../types';

let genAI: GoogleGenAI | null = null;

const getAIClient = () => {
  if (!genAI) {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      console.error("API_KEY is missing in environment variables.");
      return null;
    }
    genAI = new GoogleGenAI({ apiKey });
  }
  return genAI;
};

export const generateWeatherInsight = async (data: WeatherData): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return "AI services unavailable.";

  const locationContext = data.location.city === 'Current Location' 
    ? `Current Location (Coordinates: ${data.location.lat}, ${data.location.lng})`
    : data.location.city;

  const prompt = `
    You are a witty, helpful personal weather assistant app named "SkyCast".
    The current weather data for ${locationContext} is:
    - Condition: ${data.current.condition}
    - Temp: ${data.current.temp}°C (Feels like ${data.current.feelsLike}°C)
    - Humidity: ${data.current.humidity}%
    - Wind: ${data.current.windSpeed} km/h
    - UV Index: ${data.current.uvIndex}
    - Alerts: ${data.alerts.length > 0 ? data.alerts[0].title : "None"}

    Provide a short, 2-sentence insight. 
    1st sentence: Summary of the vibe based on the location/weather.
    2nd sentence: Recommendation (clothing, activity, or safety).
    Keep it modern and slightly fun.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Unable to generate insight right now.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Local weather data loaded. AI insight unavailable.";
  }
};

