import { WeatherData, HourlyForecast, DailyForecast, Alert } from './types';

// Helper to generate mock weather data since we don't have a real weather API key
// In a production app, this would be replaced by calls to OpenWeatherMap or Tomorrow.io
export const generateMockWeather = (city: string, lat?: number, lng?: number, district?: string): WeatherData => {
  const conditions = ['Sunny', 'Cloudy', 'Rain', 'Partly Cloudy', 'Storm'] as const;

  // Coordinates for default cities to ensure location data is consistent
  const cityCoords: Record<string, {lat: number, lng: number}> = {
    'São Paulo': { lat: -23.5505, lng: -46.6333 },
    'Rio de Janeiro': { lat: -22.9068, lng: -43.1729 },
    'Lisbon': { lat: 38.7223, lng: -9.1393 },
    'New York': { lat: 40.7128, lng: -74.0060 },
    'Tokyo': { lat: 35.6762, lng: 139.6503 },
    'London': { lat: 51.5074, lng: -0.1278 }
  };

  let finalLat = lat;
  let finalLng = lng;

  // If coordinates weren't provided (manual city selection), try to find them
  if (finalLat === undefined || finalLng === undefined) {
    if (cityCoords[city]) {
      finalLat = cityCoords[city].lat;
      finalLng = cityCoords[city].lng;
    } else {
      // Fallback defaults
      finalLat = 38.7223;
      finalLng = -9.1393;
    }
  }

  const currentCondition = conditions[Math.floor(Math.random() * conditions.length)];
  const baseTemp = 20 + Math.random() * 10; // 20-30 degrees C

  const hourly: HourlyForecast[] = Array.from({ length: 24 }).map((_, i) => {
    const hour = (new Date().getHours() + i) % 24;
    return {
      time: `${hour.toString().padStart(2, '0')}:00`,
      temp: Math.round(baseTemp + Math.sin(i / 3) * 5),
      precipChance: Math.floor(Math.random() * 30),
      condition: conditions[Math.floor(Math.random() * conditions.length)],
    };
  });

  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const daily: DailyForecast[] = Array.from({ length: 7 }).map((_, i) => {
    const date = new Date();
    date.setDate(date.getDate() + i);
    return {
      day: days[date.getDay()],
      minTemp: Math.round(baseTemp - 5 - Math.random() * 3),
      maxTemp: Math.round(baseTemp + 5 + Math.random() * 3),
      condition: conditions[Math.floor(Math.random() * conditions.length)],
    };
  });

  const alerts: Alert[] = [];
  if (Math.random() > 0.8) {
    alerts.push({
      id: 'alert-1',
      severity: 'severe',
      title: 'Severe Thunderstorm Warning',
      description: 'Strong winds and heavy rain expected in your area until 6:00 PM.',
      issuedAt: '10:00 AM'
    });
  }

  // Determine display district
  let districtName = district;

  if (!districtName) {
    if (city === 'Current Location') {
       districtName = `Lat: ${finalLat.toFixed(2)}, Lng: ${finalLng.toFixed(2)}`;
    } else {
       districtName = 'Downtown';
    }
  }

  return {
    location: {
      city: city,
      district: districtName,
      lat: finalLat,
      lng: finalLng
    },
    current: {
      temp: Math.round(baseTemp),
      feelsLike: Math.round(baseTemp + 2),
      humidity: 45 + Math.floor(Math.random() * 20),
      windSpeed: 12 + Math.floor(Math.random() * 10),
      uvIndex: Math.floor(Math.random() * 10),
      condition: currentCondition,
      description: currentCondition === 'Sunny' ? 'Clear sky' : 'Overcast clouds',
      aqi: 35
    },
    hourly,
    daily,
    alerts
  };
};

