import { WeatherData, HourlyForecast, DailyForecast, Alert } from '../types';

// WMO Weather interpretation codes (WW)
// https://open-meteo.com/en/docs
const getWeatherCondition = (code: number): { condition: 'Sunny' | 'Cloudy' | 'Rain' | 'Storm' | 'Partly Cloudy', description: string } => {
  if (code === 0) return { condition: 'Sunny', description: 'Clear sky' };
  if (code === 1) return { condition: 'Sunny', description: 'Mainly clear' };
  if (code === 2) return { condition: 'Partly Cloudy', description: 'Partly cloudy' };
  if (code === 3) return { condition: 'Cloudy', description: 'Overcast' };
  if ([45, 48].includes(code)) return { condition: 'Cloudy', description: 'Fog' };
  if ([51, 53, 55, 56, 57].includes(code)) return { condition: 'Rain', description: 'Drizzle' };
  if ([61, 63, 65, 66, 67].includes(code)) return { condition: 'Rain', description: 'Rain' };
  if ([71, 73, 75, 77].includes(code)) return { condition: 'Rain', description: 'Snow' }; 
  if ([80, 81, 82].includes(code)) return { condition: 'Rain', description: 'Showers' };
  if ([85, 86].includes(code)) return { condition: 'Rain', description: 'Snow showers' };
  if ([95, 96, 99].includes(code)) return { condition: 'Storm', description: 'Thunderstorm' };

  return { condition: 'Sunny', description: 'Clear' };
};

export const fetchWeatherData = async (lat: number, lng: number, city: string, district?: string): Promise<WeatherData> => {
  // Fetch parameters: current weather, hourly forecast, daily forecast
  const url = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lng}&current=temperature_2m,relative_humidity_2m,apparent_temperature,precipitation,weather_code,wind_speed_10m&hourly=temperature_2m,precipitation_probability,weather_code&daily=weather_code,temperature_2m_max,temperature_2m_min&timezone=auto`;

  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error('Weather data fetch failed');
    const data = await response.json();

    const currentCondition = getWeatherCondition(data.current.weather_code);

    // Process Hourly Data (next 24h)
    const hourly: HourlyForecast[] = data.hourly.time.slice(0, 24).map((timeStr: string, index: number) => {
      const date = new Date(timeStr);
      const hours = date.getHours().toString().padStart(2, '0');
      const cond = getWeatherCondition(data.hourly.weather_code[index]);

      return {
        time: `${hours}:00`,
        temp: Math.round(data.hourly.temperature_2m[index]),
        precipChance: data.hourly.precipitation_probability[index],
        condition: cond.condition
      };
    });

    // Process Daily Data (next 7 days)
    const daily: DailyForecast[] = data.daily.time.map((timeStr: string, index: number) => {
      // Ensure we parse the date correctly regardless of timezone issues by appending T00:00
      const date = new Date(`${timeStr}T00:00:00`); 
      const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      const cond = getWeatherCondition(data.daily.weather_code[index]);

      return {
        day: days[date.getDay()],
        minTemp: Math.round(data.daily.temperature_2m_min[index]),
        maxTemp: Math.round(data.daily.temperature_2m_max[index]),
        condition: cond.condition
      };
    });

    // Generate alerts based on real data conditions
    const alerts: Alert[] = [];
    const code = data.current.weather_code;
    const windSpeed = data.current.wind_speed_10m;
    const precip = data.current.precipitation;
    const temp = data.current.temperature_2m;

    // 1. Storm Alerts (WMO codes for Thunderstorm)
    if ([95, 96, 99].includes(code)) {
      alerts.push({
        id: 'storm-alert',
        severity: 'severe',
        title: 'Thunderstorm Warning',
        description: 'Thunderstorms detected in the area. Seek shelter and avoid open areas.',
        issuedAt: 'Now'
      });
    }

    // 2. Snow/Ice Alerts
    if ([71, 73, 75, 77, 85, 86].includes(code)) {
      alerts.push({
        id: 'snow-alert',
        severity: 'moderate',
        title: 'Snow & Ice Advisory',
        description: 'Snowfall detected. Roads may be slippery. Drive with caution.',
        issuedAt: 'Now'
      });
    }

    // 3. High Wind Alerts (> 40 km/h is breezy, > 60 is dangerous)
    if (windSpeed > 40) {
      alerts.push({
        id: 'wind-alert',
        severity: windSpeed > 60 ? 'severe' : 'moderate',
        title: 'High Wind Warning',
        description: `Current wind speeds are high (${windSpeed} km/h). Secure loose items outside.`,
        issuedAt: 'Now'
      });
    }

    // 4. Heavy Rain (> 5mm/h is roughly heavy)
    if (precip > 5) {
      alerts.push({
        id: 'rain-alert',
        severity: 'moderate',
        title: 'Heavy Rain Detected',
        description: `Significant precipitation (${precip}mm). Visibility may be reduced.`,
        issuedAt: 'Now'
      });
    }

    // 5. Extreme Heat (> 35°C)
    if (temp > 35) {
      alerts.push({
        id: 'heat-alert',
        severity: 'extreme',
        title: 'Excessive Heat Warning',
        description: `Temperatures are very high (${temp}°C). Stay hydrated and avoid direct sun.`,
        issuedAt: 'Now'
      });
    }

    // 6. Freezing Conditions (< 0°C)
    if (temp < 0) {
      alerts.push({
        id: 'freeze-alert',
        severity: 'moderate',
        title: 'Freeze Warning',
        description: `Temperatures are below freezing (${temp}°C). Protect plants and pets.`,
        issuedAt: 'Now'
      });
    }

    // Return formatted data
    return {
      location: {
        city,
        district: district || '',
        lat,
        lng
      },
      current: {
        temp: Math.round(data.current.temperature_2m),
        feelsLike: Math.round(data.current.apparent_temperature),
        humidity: data.current.relative_humidity_2m,
        windSpeed: Math.round(data.current.wind_speed_10m),
        uvIndex: 5, // Note: Basic Open-Meteo doesn't provide UV. Would require extra params/API.
        condition: currentCondition.condition,
        description: currentCondition.description,
        aqi: 30 // Note: AQI requires a separate API call usually.
      },
      hourly,
      daily,
      alerts
    };

  } catch (error) {
    console.error("Error fetching weather data:", error);
    // Re-throw so the UI can handle the error state if needed
    throw error;
  }
};

import React, { useEffect, useState, useMemo } from 'react';

interface RadarViewProps {
  condition?: string; // 'Sunny', 'Rain', 'Storm', 'Cloudy', etc.
}

interface Blip {
  id: number;
  x: number;
  y: number;
  r: number; // radius
  opacity: number;
  color: string;
}

const RadarView: React.FC<RadarViewProps> = ({ condition = 'Sunny' }) => {
  const [rotation, setRotation] = useState(0);
  const [blips, setBlips] = useState<Blip[]>([]);

  // Rotate the sweep line
  useEffect(() => {
    let frameId: number;
    const animate = () => {
      setRotation(prev => (prev + 1.5) % 360);
      frameId = requestAnimationFrame(animate);
    };
    frameId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frameId);
  }, []);

  // Generate "Fake" radar returns based on actual weather condition
  useEffect(() => {
    const generateBlips = () => {
      const newBlips: Blip[] = [];
      const count = condition === 'Storm' ? 25 : condition === 'Rain' ? 15 : condition === 'Cloudy' ? 5 : 0;

      const colors = condition === 'Storm' 
        ? ['#ef4444', '#eab308', '#f97316'] // Red, Yellow, Orange
        : ['#3b82f6', '#10b981', '#6366f1']; // Blue, Green, Indigo

      for (let i = 0; i < count; i++) {
        // Random position within a circle, concentrated somewhat centrally
        const angle = Math.random() * Math.PI * 2;
        const dist = Math.random() * 40 + (Math.random() * 40); // 0 to 80 radius

        newBlips.push({
          id: i,
          x: 50 + Math.cos(angle) * (dist / 2), // 0-100 scale
          y: 50 + Math.sin(angle) * (dist / 2),
          r: Math.random() * 8 + 4,
          opacity: Math.random() * 0.5 + 0.2,
          color: colors[Math.floor(Math.random() * colors.length)]
        });
      }
      setBlips(newBlips);
    };

    generateBlips();
  }, [condition]);

  return (
    <div className="relative w-full h-72 bg-slate-950 rounded-xl overflow-hidden border border-slate-700 shadow-[inset_0_0_20px_rgba(0,0,0,0.5)] group">

      {/* Grid Layer */}
      <div className="absolute inset-0 z-0">
        <svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="none">
           {/* Grid Lines */}
           <defs>
            <pattern id="radarGrid" width="10" height="10" patternUnits="userSpaceOnUse">
              <path d="M 10 0 L 0 0 0 10" fill="none" stroke="#1e293b" strokeWidth="0.5"/>
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#radarGrid)" />

          {/* Range Rings */}
          <circle cx="50" cy="50" r="20" fill="none" stroke="#334155" strokeWidth="0.5" strokeDasharray="2 2" />
          <circle cx="50" cy="50" r="40" fill="none" stroke="#334155" strokeWidth="0.5" strokeDasharray="2 2" />

          {/* Crosshairs */}
          <line x1="50" y1="0" x2="50" y2="100" stroke="#334155" strokeWidth="0.5" />
          <line x1="0" y1="50" x2="100" y2="50" stroke="#334155" strokeWidth="0.5" />
        </svg>
      </div>

      {/* Storm Cells Layer */}
      <div className="absolute inset-0 z-10 filter blur-[8px] mix-blend-screen">
        <svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="none">
          {blips.map((blip) => (
             <circle 
               key={blip.id}
               cx={blip.x} 
               cy={blip.y} 
               r={blip.r} 
               fill={blip.color}
               opacity={blip.opacity}
               className="animate-pulse"
             />
          ))}
        </svg>
      </div>

      {/* Sweep Layer */}
      <div 
        className="absolute inset-0 z-20 flex items-center justify-center pointer-events-none"
      >
        <div 
          className="w-[150%] h-[150%] bg-[conic-gradient(from_0deg,transparent_0deg,transparent_270deg,rgba(16,185,129,0.1)_320deg,rgba(16,185,129,0.4)_360deg)]"
          style={{ 
            transform: `rotate(${rotation}deg)`,
            borderRadius: '50%'
          }}
        />
      </div>

      {/* UI Overlay */}
      <div className="absolute inset-0 z-30 p-3 pointer-events-none flex flex-col justify-between">
        <div className="flex justify-between items-start">
           <div className="text-[10px] font-mono text-emerald-500/80 bg-slate-900/80 px-2 py-1 border border-emerald-900/50 rounded">
             DOPPLER RADAR<br/>
             <span className="text-slate-400">RANGE: 50KM</span>
           </div>
           <div className="text-[10px] font-mono text-slate-400 text-right">
             MODE: {condition === 'Sunny' ? 'CLEAR AIR' : 'PRECIPITATION'}<br/>
             UPDATED: LIVE
           </div>
        </div>

        <div className="flex justify-between items-end text-[10px] font-mono text-slate-600">
           <span>-122.4</span>
           <span>37.7</span>
        </div>
      </div>

      {/* Center Dot */}
      <div className="absolute top-1/2 left-1/2 w-2 h-2 bg-emerald-500 rounded-full -translate-x-1/2 -translate-y-1/2 z-40 shadow-[0_0_10px_#10b981]"></div>
    </div>
  );
};

