import { CITY_COORDINATES } from './constants';
import { fetchWeatherData } from './services/weatherService';
import CurrentConditions from './components/CurrentConditions';
import ForecastChart from './components/ForecastChart';
import RadarView from './components/RadarView';
import AIWeatherInsight from './components/AIWeatherInsight';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [weatherData, setWeatherData] = useState<WeatherData | null>(null);
  const [showMobileMenu, setShowMobileMenu] = useState(false);

  // Search State
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isSearchOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [isSearchOpen]);

  // Function to load weather data using the service
  const loadWeather = async (lat: number, lng: number, locationName: string, district?: string) => {
    try {
      setAppState(AppState.LOADING);
      const data = await fetchWeatherData(lat, lng, locationName, district);
      setWeatherData(data);
      setAppState(AppState.DASHBOARD);
      setIsSearchOpen(false);
      setSearchQuery("");
    } catch (error) {
      console.error("Failed to load weather", error);
      alert("Failed to fetch weather data. Please check your connection.");
      setAppState(AppState.DASHBOARD); // Go back to dashboard if possible, or onboarding if null
    }
  };

  const handleGrantLocation = () => {
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser.");
      return;
    }

    setAppState(AppState.LOADING);

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        let locationName = "Current Location";
        let districtName = "";

        try {
          // Use OpenStreetMap Nominatim for reverse geocoding
          const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`);
          if (response.ok) {
            const data = await response.json();
            if (data && data.address) {
              locationName = data.address.city || 
                             data.address.town || 
                             data.address.village || 
                             data.address.municipality ||
                             "Detected Location";

              districtName = data.address.suburb || 
                             data.address.neighbourhood || 
                             data.address.quarter || 
                             "";

              if (districtName === locationName) districtName = "";
            }
          }
        } catch (error) {
          console.error("Reverse geocoding failed", error);
          locationName = `${latitude.toFixed(2)}, ${longitude.toFixed(2)}`;
        }

        loadWeather(latitude, longitude, locationName, districtName);
      },
      (error) => {
        console.error("Error getting location", error);
        alert("Unable to retrieve your location.");
        setAppState(AppState.ONBOARDING);
      },
      { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
    );
  };

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setAppState(AppState.LOADING);

    try {
      // First check if it matches a hardcoded city for instant load (optional optimization)
      const normalizedQuery = searchQuery.trim();
      const predefined = Object.keys(CITY_COORDINATES).find(c => c.toLowerCase() === normalizedQuery.toLowerCase());

      if (predefined) {
        const coords = CITY_COORDINATES[predefined];
        loadWeather(coords.lat, coords.lng, predefined);
        return;
      }

      // If not, use Nominatim Search API
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(normalizedQuery)}&limit=1`);

      if (response.ok) {
        const results = await response.json();
        if (results && results.length > 0) {
          const { lat, lon, display_name, name } = results[0];
          // Use the short name if available, otherwise the display name
          const cityName = name || display_name.split(',')[0];
          loadWeather(parseFloat(lat), parseFloat(lon), cityName);
        } else {
          alert("City not found. Please try another name.");
          setAppState(AppState.DASHBOARD);
          setIsSearchOpen(true);
        }
      } else {
        throw new Error("Search API failed");
      }
    } catch (error) {
      console.error("Search failed", error);
      alert("Unable to search for city. Please check connection.");
      setAppState(AppState.DASHBOARD);
    }
  };

  if (appState === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 p-6 text-center">
        <div className="w-24 h-24 bg-sky-500 rounded-full flex items-center justify-center mb-8 shadow-2xl shadow-sky-500/20 animate-bounce">
          <Navigation className="w-12 h-12 text-white" />
        </div>
        <h1 className="text-4xl font-bold text-white mb-4">SkyCast AI</h1>
        <p className="text-slate-400 max-w-sm mb-8">
          Hyperlocal forecasts. Search any city or use your precise location.
        </p>

        <div className="flex flex-col gap-4 w-full max-w-xs">
            <button
            onClick={handleGrantLocation}
            className="bg-sky-500 hover:bg-sky-400 text-white px-8 py-4 rounded-2xl font-semibold text-lg transition-all shadow-lg hover:shadow-sky-500/30 flex items-center justify-center gap-2"
            >
            <MapPin className="w-5 h-5" />
            Use My Location
            </button>

            <form onSubmit={handleSearchSubmit} className="relative">
                <input 
                    type="text" 
                    placeholder="Or search city..." 
                    className="w-full bg-slate-800 border border-slate-700 text-white px-4 py-4 rounded-2xl outline-none focus:border-sky-500 text-center"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
                 <button 
                    type="submit"
                    className="absolute right-3 top-1/2 -translate-y-1/2 p-2 text-slate-400 hover:text-white"
                 >
                     <Search className="w-5 h-5" />
                 </button>
            </form>
        </div>
      </div>
    );
  }

  if (appState === AppState.LOADING || !weatherData) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <div className="flex flex-col items-center">
          <div className="w-12 h-12 border-4 border-sky-500 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-slate-400 animate-pulse">
            {searchQuery ? `Searching for "${searchQuery}"...` : "Acquiring satellite data..."}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 text-slate-50 pb-20 md:pb-0">

      {/* Top Navigation */}
      <header className="fixed top-0 w-full bg-slate-900/80 backdrop-blur-md border-b border-slate-800 z-50 px-4 py-3 flex items-center justify-between">

        {/* Brand / Logo */}
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-sky-500 rounded-lg flex items-center justify-center">
             <Navigation className="w-5 h-5 text-white" />
          </div>
          <span className="font-bold text-lg hidden md:block">SkyCast AI</span>
        </div>

        {/* Action Bar */}
        <div className="flex items-center gap-2 md:gap-3 flex-1 justify-end">

           {/* Search Bar - conditionally rendered */}
           {isSearchOpen ? (
               <form onSubmit={handleSearchSubmit} className="flex-1 max-w-md relative animate-in fade-in zoom-in duration-200">
                   <input 
                        ref={searchInputRef}
                        type="text" 
                        className="w-full bg-slate-800 border border-sky-500 text-white text-sm rounded-lg pl-3 pr-10 py-2 outline-none"
                        placeholder="Search city..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        onBlur={() => {
                            if(!searchQuery) setIsSearchOpen(false);
                        }}
                   />
                   <button 
                    type="button" 
                    onClick={() => {
                        setIsSearchOpen(false);
                        setSearchQuery("");
                    }}
                    className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white"
                   >
                       <X className="w-4 h-4" />
                   </button>
               </form>
           ) : (
             <>
                <button 
                    onClick={() => setIsSearchOpen(true)}
                    className="bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-300 px-3 py-2 rounded-lg transition-colors flex items-center gap-2 text-sm"
                >
                    <Search className="w-4 h-4" />
                    <span className="hidden sm:inline">Search City</span>
