import React, { useEffect, useState, useMemo } from 'react';
import { Cloud, CloudRain, CloudSnow, Sun, Zap } from 'lucide-react';

interface RadarViewProps {
  condition?: string; // 'Sunny', 'Rain', 'Storm', 'Cloudy', 'Partly Cloudy', etc.
}

const RadarView: React.FC<RadarViewProps> = ({ condition = 'Sunny' }) => {
  const [time, setTime] = useState(Date.now());

  // Animation loop for drifting clouds/weather
  useEffect(() => {
    let frameId: number;
    const animate = () => {
      setTime(Date.now());
      frameId = requestAnimationFrame(animate);
    };
    frameId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frameId);
  }, []);

  // Determine weather parameters
  const weatherState = useMemo(() => {
    const c = condition.toLowerCase();
    const isStorm = c.includes('storm') || c.includes('thunder');
    const isRain = c.includes('rain') || c.includes('drizzle') || c.includes('shower');
    const isSnow = c.includes('snow') || c.includes('ice') || c.includes('flurry');
    const isCloudy = c.includes('cloud') || c.includes('overcast');
    const isPartly = c.includes('partly');
    const isClear = !isStorm && !isRain && !isSnow && !isCloudy && !isPartly;

    return { isStorm, isRain, isSnow, isCloudy, isPartly, isClear };
  }, [condition]);

  // Generate clouds
  const clouds = useMemo(() => {
    if (weatherState.isClear) return [];

    const count = weatherState.isPartly ? 3 : 8;
    const baseColor = (weatherState.isRain || weatherState.isStorm) ? '#64748b' : '#f8fafc'; // Slate-500 vs Slate-50

    return Array.from({ length: count }).map((_, i) => ({
      id: i,
      x: Math.random() * 100,
      y: Math.random() * 80 + 10,
      r: Math.random() * 30 + 20, // Large radius for fluffy look
      opacity: (weatherState.isRain || weatherState.isStorm) ? 0.8 : 0.4,
      speed: Math.random() * 0.05 + 0.02,
      color: baseColor
    }));
  }, [weatherState]);

  // Generate precipitation (Rain/Snow)
  const precipitation = useMemo(() => {
    if (!weatherState.isRain && !weatherState.isSnow && !weatherState.isStorm) return [];

    const count = weatherState.isStorm ? 100 : 60;
    return Array.from({ length: count }).map((_, i) => ({
      id: i,
      x: Math.random() * 100,
      y: Math.random() * 100,
      speed: Math.random() * 1 + 0.5,
      length: weatherState.isSnow ? 1 : Math.random() * 5 + 2,
    }));
  }, [weatherState]);

  return (
    <div className="relative w-full h-72 bg-[#0f172a] rounded-xl overflow-hidden border border-slate-700 shadow-lg group">

      {/* 1. Base Map Layer (Stylized Landmass) */}
      <div className="absolute inset-0 bg-[#020617]">
        {/* Abstract Coastline/Land */}
        <svg width="100%" height="100%" preserveAspectRatio="none" viewBox="0 0 100 100">
           <path 
             d="M0 100 L0 30 Q20 40 40 20 T80 30 T100 10 V100 Z" 
             fill="#1e293b" // Slate 800 (Land)
             opacity="0.5"
           />
           <path 
             d="M60 100 Q50 70 80 60 T100 80 V100 Z" 
             fill="#334155" // Slate 700 (Highland)
             opacity="0.3"
           />
           {/* Grid Lines for Satellite feel */}
           <line x1="0" y1="25" x2="100" y2="25" stroke="#1e293b" strokeWidth="0.2" />
           <line x1="0" y1="50" x2="100" y2="50" stroke="#1e293b" strokeWidth="0.2" />
           <line x1="0" y1="75" x2="100" y2="75" stroke="#1e293b" strokeWidth="0.2" />
           <line x1="25" y1="0" x2="25" y2="100" stroke="#1e293b" strokeWidth="0.2" />
           <line x1="50" y1="0" x2="50" y2="100" stroke="#1e293b" strokeWidth="0.2" />
           <line x1="75" y1="0" x2="75" y2="100" stroke="#1e293b" strokeWidth="0.2" />
        </svg>
      </div>

      {/* 2. Cloud Layer (Satellite View) */}
      <div className="absolute inset-0 filter blur-xl">
        <svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="none">
          {clouds.map((cloud) => {
            // Animate X position
            const offsetX = (time * cloud.speed) % 150 - 25; 
            return (
              <circle 
                key={cloud.id}
                cx={cloud.x + offsetX} 
                cy={cloud.y} 
                r={cloud.r} 
                fill={cloud.color}
                opacity={cloud.opacity}
              />
            );
          })}
        </svg>
      </div>

      {/* 3. Storm Lighting Layer */}
      {weatherState.isStorm && (
        <div className="absolute inset-0 bg-white/20 z-10 animate-[pulse_3s_ease-in-out_infinite] opacity-0 mix-blend-overlay"></div>
      )}

      {/* 4. Precipitation Layer */}
      {(weatherState.isRain || weatherState.isSnow || weatherState.isStorm) && (
        <div className="absolute inset-0 z-20 opacity-60">
           <svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="none">
             {precipitation.map((drop) => {
               // Rain falls down, Snow floats
               const yPos = (drop.y + (time * (weatherState.isSnow ? 0.005 : 0.05) * drop.speed)) % 100;
               return weatherState.isSnow ? (
                 <circle key={drop.id} cx={drop.x} cy={yPos} r={0.5} fill="white" />
               ) : (
                 <line 
                    key={drop.id}
                    x1={drop.x} 
                    y1={yPos} 
                    x2={drop.x - 0.5} // Slight angle for rain
                    y2={yPos + drop.length} 
                    stroke="#7dd3fc" 
                    strokeWidth="0.3" 
                 />
               );
             })}
           </svg>
        </div>
      )}

      {/* 5. UI Overlay */}
      <div className="absolute inset-0 z-30 p-3 pointer-events-none flex flex-col justify-between">
        <div className="flex justify-between items-start">
           <div className="flex items-center gap-2 text-[10px] font-mono text-slate-300 bg-slate-900/80 px-2 py-1 border border-slate-700 rounded backdrop-blur-sm">
             <div className={`w-2 h-2 rounded-full ${weatherState.isClear ? 'bg-emerald-500' : 'bg-amber-500'} animate-pulse`}></div>
             SATELLITE VIEW - {condition.toUpperCase()}
           </div>
        </div>

        <div className="flex justify-between items-end">
           <div className="text-[10px] font-mono text-slate-500">
             BAND: IR/VIS MIX<br/>
             RES: 1KM
           </div>

           {/* Legend Icon */}
           <div className="bg-slate-900/80 p-1.5 rounded border border-slate-700 text-slate-300 backdrop-blur-sm">
              {weatherState.isClear && <Sun className="w-4 h-4 text-amber-400" />}
              {weatherState.isRain && <CloudRain className="w-4 h-4 text-blue-400" />}
              {weatherState.isSnow && <CloudSnow className="w-4 h-4 text-white" />}
              {weatherState.isStorm && <Zap className="w-4 h-4 text-purple-400" />}
              {(weatherState.isCloudy || weatherState.isPartly) && <Cloud className="w-4 h-4 text-slate-300" />}
           </div>
        </div>
      </div>

      {/* Location Marker (Center) */}
      <div className="absolute top-1/2 left-1/2 w-3 h-3 border-2 border-sky-500 rounded-full -translate-x-1/2 -translate-y-1/2 z-30 shadow-[0_0_10px_#0ea5e9]">
        <div className="absolute top-1/2 left-1/2 w-1 h-1 bg-white rounded-full -translate-x-1/2 -translate-y-1/2"></div>
      </div>

    </div>
  );
};

