import { CITY_COORDINATES } from './constants';
import { fetchWeatherData } from './services/weatherService';
import CurrentConditions from './components/CurrentConditions';
import ForecastChart from './components/ForecastChart';
import RadarView from './components/RadarView';
import AIWeatherInsight from './components/AIWeatherInsight';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [weatherData, setWeatherData] = useState<WeatherData | null>(null);
  const [showMobileMenu, setShowMobileMenu] = useState(false);

  // Search State
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isSearchOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [isSearchOpen]);

  // Function to load weather data using the service
  const loadWeather = async (lat: number, lng: number, locationName: string, district?: string) => {
    try {
      setAppState(AppState.LOADING);
      const data = await fetchWeatherData(lat, lng, locationName, district);
      setWeatherData(data);
      setAppState(AppState.DASHBOARD);
      setIsSearchOpen(false);
      setSearchQuery("");
    } catch (error) {
      console.error("Failed to load weather", error);
      alert("Failed to fetch weather data. Please check your connection.");
      setAppState(AppState.DASHBOARD); // Go back to dashboard if possible, or onboarding if null
    }
  };

  const handleGrantLocation = () => {
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser.");
      return;
    }

    setAppState(AppState.LOADING);

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        let locationName = "Current Location";
        let districtName = "";

        try {
          // Use OpenStreetMap Nominatim for reverse geocoding
          const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`);
          if (response.ok) {
            const data = await response.json();
            if (data && data.address) {
              locationName = data.address.city || 
                             data.address.town || 
                             data.address.village || 
                             data.address.municipality ||
                             "Detected Location";

              districtName = data.address.suburb || 
                             data.address.neighbourhood || 
                             data.address.quarter || 
                             "";

              if (districtName === locationName) districtName = "";
            }
          }
        } catch (error) {
          console.error("Reverse geocoding failed", error);
          locationName = `${latitude.toFixed(2)}, ${longitude.toFixed(2)}`;
        }

        loadWeather(latitude, longitude, locationName, districtName);
      },
      (error) => {
        console.error("Error getting location", error);
        alert("Unable to retrieve your location.");
        setAppState(AppState.ONBOARDING);
      },
      { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
    );
  };

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setAppState(AppState.LOADING);

    try {
      // First check if it matches a hardcoded city for instant load (optional optimization)
      const normalizedQuery = searchQuery.trim();
      const predefined = Object.keys(CITY_COORDINATES).find(c => c.toLowerCase() === normalizedQuery.toLowerCase());

      if (predefined) {
        const coords = CITY_COORDINATES[predefined];
        loadWeather(coords.lat, coords.lng, predefined);
        return;
      }

      // If not, use Nominatim Search API
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(normalizedQuery)}&limit=1`);

      if (response.ok) {
        const results = await response.json();
        if (results && results.length > 0) {
          const { lat, lon, display_name, name } = results[0];
          // Use the short name if available, otherwise the display name
          const cityName = name || display_name.split(',')[0];
          loadWeather(parseFloat(lat), parseFloat(lon), cityName);
        } else {
          alert("City not found. Please try another name.");
          setAppState(AppState.DASHBOARD);
          setIsSearchOpen(true);
        }
      } else {
        throw new Error("Search API failed");
      }
    } catch (error) {
      console.error("Search failed", error);
      alert("Unable to search for city. Please check connection.");
      setAppState(AppState.DASHBOARD);
    }
  };

  if (appState === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 p-6 text-center">
        <div className="w-24 h-24 bg-sky-500 rounded-full flex items-center justify-center mb-8 shadow-2xl shadow-sky-500/20 animate-bounce">
          <Navigation className="w-12 h-12 text-white" />
        </div>
        <h1 className="text-4xl font-bold text-white mb-4">SkyCast AI</h1>
        <p className="text-slate-400 max-w-sm mb-8">
          Hyperlocal forecasts. Search any city or use your precise location.
        </p>

        <div className="flex flex-col gap-4 w-full max-w-xs">
            <button
            onClick={handleGrantLocation}
            className="bg-sky-500 hover:bg-sky-400 text-white px-8 py-4 rounded-2xl font-semibold text-lg transition-all shadow-lg hover:shadow-sky-500/30 flex items-center justify-center gap-2"
            >
            <MapPin className="w-5 h-5" />
            Use My Location
            </button>

            <form onSubmit={handleSearchSubmit} className="relative">
                <input 
                    type="text" 
                    placeholder="Or search city..." 
                    className="w-full bg-slate-800 border border-slate-700 text-white px-4 py-4 rounded-2xl outline-none focus:border-sky-500 text-center"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
                 <button 
                    type="submit"
                    className="absolute right-3 top-1/2 -translate-y-1/2 p-2 text-slate-400 hover:text-white"
                 >
                     <Search className="w-5 h-5" />
                 </button>
            </form>
        </div>
      </div>
    );
  }

  if (appState === AppState.LOADING || !weatherData) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <div className="flex flex-col items-center">
          <div className="w-12 h-12 border-4 border-sky-500 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-slate-400 animate-pulse">
            {searchQuery ? `Searching for "${searchQuery}"...` : "Acquiring satellite data..."}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 text-slate-50 pb-20 md:pb-0">

      {/* Top Navigation */}
      <header className="fixed top-0 w-full bg-slate-900/80 backdrop-blur-md border-b border-slate-800 z-50 px-4 py-3 flex items-center justify-between">

        {/* Brand / Logo */}
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-sky-500 rounded-lg flex items-center justify-center">
             <Navigation className="w-5 h-5 text-white" />
          </div>
          <span className="font-bold text-lg hidden md:block">SkyCast AI</span>
        </div>

        {/* Action Bar */}
        <div className="flex items-center gap-2 md:gap-3 flex-1 justify-end">

           {/* Search Bar - conditionally rendered */}
           {isSearchOpen ? (
               <form onSubmit={handleSearchSubmit} className="flex-1 max-w-md relative animate-in fade-in zoom-in duration-200">
                   <input 
                        ref={searchInputRef}
                        type="text" 
                        className="w-full bg-slate-800 border border-sky-500 text-white text-sm rounded-lg pl-3 pr-10 py-2 outline-none"
                        placeholder="Search city..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        onBlur={() => {
                            if(!searchQuery) setIsSearchOpen(false);
                        }}
                   />
                   <button 
                    type="button" 
                    onClick={() => {
                        setIsSearchOpen(false);
                        setSearchQuery("");
                    }}
                    className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white"
                   >
                       <X className="w-4 h-4" />
                   </button>
               </form>
           ) : (
             <>
                <button 
                    onClick={() => setIsSearchOpen(true)}
                    className="bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-300 px-3 py-2 rounded-lg transition-colors flex items-center gap-2 text-sm"
                >
                    <Search className="w-4 h-4" />
                    <span className="hidden sm:inline">Search City</span>
                </button>

                <div className="h-6 w-px bg-slate-800 mx-1"></div>

                <button 
                    onClick={handleGrantLocation}
                    className="bg-slate-800 hover:bg-slate-700 border border-slate-700 text-sky-400 p-2 rounded-lg transition-colors flex items-center justify-center"
                    title="Use Current Location"
                >
                    <LocateFixed className="w-5 h-5" />
                </button>
             </>
           )}

            {!isSearchOpen && (
                <>
                    <button className="p-2 hover:bg-slate-800 rounded-full relative">
                    <Bell className="w-5 h-5 text-slate-400" />
                    {weatherData.alerts.length > 0 && (
                        <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full"></span>
                    )}
                    </button>
                    <button 
                    className="md:hidden p-2 hover:bg-slate-800 rounded-full"
                    onClick={() => setShowMobileMenu(!showMobileMenu)}
                    >
                    <Menu className="w-5 h-5 text-slate-400" />
                    </button>
                </>
            )}
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 pt-20 max-w-5xl">

        {/* Severe Weather Alert Banner */}
        {weatherData.alerts.map(alert => (
          <div key={alert.id} className="mb-6 bg-red-500/10 border border-red-500/50 rounded-xl p-4 flex items-start gap-4 animate-pulse">
            <ShieldAlert className="w-6 h-6 text-red-500 shrink-0 mt-1" />
            <div>
              <h3 className="font-bold text-red-400">{alert.title}</h3>
              <p className="text-sm text-red-200/80">{alert.description}</p>
              <p className="text-xs text-red-300 mt-1">Issued: {alert.issuedAt}</p>
            </div>
          </div>
        ))}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

          {/* Left Column: Main Info */}
          <div className="md:col-span-2 space-y-6">
            <CurrentConditions data={weatherData} />

            <div className="bg-slate-800/50 border border-slate-700/50 rounded-2xl p-6">
              <div className="flex justify-between items-center mb-6">
                <h3 className="font-semibold text-slate-200">Hourly Forecast</h3>
                <span className="text-xs text-slate-500">Next 24 Hours</span>
              </div>
              <ForecastChart data={weatherData.hourly} />
            </div>

             <div className="bg-slate-800/50 border border-slate-700/50 rounded-2xl p-6">
              <h3 className="font-semibold text-slate-200 mb-4">Interactive Radar</h3>
              <RadarView 
                condition={weatherData.current.condition} 
                lat={weatherData.location.lat}
                lng={weatherData.location.lng}
                precipChance={weatherData.hourly[0]?.precipChance || 0}
              />
            </div>
          </div>

          {/* Right Column: AI & Details */}
          <div className="space-y-6">
            <AIWeatherInsight weatherData={weatherData} />

            <div className="bg-slate-800/50 border border-slate-700/50 rounded-2xl p-6">
              <h3 className="font-semibold text-slate-200 mb-4">7-Day Forecast</h3>
              <div className="space-y-4">
                {weatherData.daily.map((day, idx) => (
                  <div key={idx} className="flex items-center justify-between text-sm group hover:bg-slate-700/30 p-2 rounded transition-colors">
                    <span className="w-12 text-slate-400 font-medium">{day.day}</span>
                    <div className="flex-1 px-4">
                       <div className="h-1.5 w-full bg-slate-700 rounded-full overflow-hidden">
                          <div 
                            className="h-full bg-gradient-to-r from-sky-500 to-amber-400"
                            style={{ 
                              width: `${Math.max(0, (day.maxTemp - day.minTemp) * 4)}%`,
                              marginLeft: `${Math.max(0, (day.minTemp + 10) * 1.5)}%` 
                            }}
                          ></div>
                       </div>
                    </div>
                    <div className="flex gap-3 text-slate-300 w-20 justify-end font-mono">
                      <span className="opacity-60">{day.minTemp}°</span>
                      <span className="font-bold">{day.maxTemp}°</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Customization / Widgets Teaser */}
            <div className="bg-slate-800/50 border border-slate-700/50 rounded-2xl p-6">
              <div className="flex items-center gap-2 mb-2">
                 <Settings className="w-4 h-4 text-slate-400" />
                 <h3 className="font-semibold text-slate-200">Customization</h3>
              </div>
              <p className="text-xs text-slate-400 mb-4">
                Personalize your dashboard widgets and notification thresholds.
              </p>
              <div className="space-y-2">
                <div className="flex items-center justify-between p-3 bg-slate-700/30 rounded-lg">
                  <span className="text-sm">Rain Alerts</span>
                  <div className="w-8 h-4 bg-sky-500 rounded-full relative cursor-pointer">
                    <div className="absolute right-0.5 top-0.5 w-3 h-3 bg-white rounded-full"></div>
                  </div>
                </div>
                 <div className="flex items-center justify-between p-3 bg-slate-700/30 rounded-lg">
                  <span className="text-sm">Daily Briefing</span>
                  <div className="w-8 h-4 bg-slate-600 rounded-full relative cursor-pointer">
                     <div className="absolute left-0.5 top-0.5 w-3 h-3 bg-white rounded-full"></div>
                  </div>
                </div>
              </div>
            </div>

          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

export interface WeatherLocation {
  city: string;
  district: string;
  lat: number;
  lng: number;
}

export interface HourlyForecast {
  time: string; // HH:00
  temp: number;
  precipChance: number;
  condition: 'Sunny' | 'Cloudy' | 'Rain' | 'Storm' | 'Partly Cloudy';
}

export interface DailyForecast {
  day: string;
  minTemp: number;
  maxTemp: number;
  precipChance: number; // Added precipitation probability
  condition: 'Sunny' | 'Cloudy' | 'Rain' | 'Storm' | 'Partly Cloudy';
}

export interface Alert {
  id: string;
  severity: 'moderate' | 'severe' | 'extreme';
  title: string;
  description: string;
  issuedAt: string;
}

export interface CurrentWeather {
  temp: number;
  feelsLike: number;
  humidity: number;
  windSpeed: number;
  uvIndex: number;
  condition: 'Sunny' | 'Cloudy' | 'Rain' | 'Storm' | 'Partly Cloudy';
  description: string;
  aqi: number; // Air Quality Index
}

export interface WeatherData {
  location: WeatherLocation;
  current: CurrentWeather;
  hourly: HourlyForecast[];
  daily: DailyForecast[];
  alerts: Alert[];
}

export enum AppState {
  ONBOARDING,
  LOADING,
  DASHBOARD,
  ERROR
}

import { WeatherData, HourlyForecast, DailyForecast, Alert } from '../types';

// WMO Weather interpretation codes (WW)
// https://open-meteo.com/en/docs
const getWeatherCondition = (code: number): { condition: 'Sunny' | 'Cloudy' | 'Rain' | 'Storm' | 'Partly Cloudy', description: string } => {
  if (code === 0) return { condition: 'Sunny', description: 'Clear sky' };
  if (code === 1) return { condition: 'Sunny', description: 'Mainly clear' };
  if (code === 2) return { condition: 'Partly Cloudy', description: 'Partly cloudy' };
  if (code === 3) return { condition: 'Cloudy', description: 'Overcast' };
  if ([45, 48].includes(code)) return { condition: 'Cloudy', description: 'Fog' };
  if ([51, 53, 55, 56, 57].includes(code)) return { condition: 'Rain', description: 'Drizzle' };
  if ([61, 63, 65, 66, 67].includes(code)) return { condition: 'Rain', description: 'Rain' };
  if ([71, 73, 75, 77].includes(code)) return { condition: 'Rain', description: 'Snow' }; 
  if ([80, 81, 82].includes(code)) return { condition: 'Rain', description: 'Showers' };
  if ([85, 86].includes(code)) return { condition: 'Rain', description: 'Snow showers' };
  if ([95, 96, 99].includes(code)) return { condition: 'Storm', description: 'Thunderstorm' };

  return { condition: 'Sunny', description: 'Clear' };
};

export const fetchWeatherData = async (lat: number, lng: number, city: string, district?: string): Promise<WeatherData> => {
  // Fetch parameters: added precipitation_probability_max to daily
  const url = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lng}&current=temperature_2m,relative_humidity_2m,apparent_temperature,precipitation,weather_code,wind_speed_10m&hourly=temperature_2m,precipitation_probability,weather_code&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_probability_max&timezone=auto`;

  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error('Weather data fetch failed');
    const data = await response.json();

    const currentCondition = getWeatherCondition(data.current.weather_code);

    // Process Hourly Data (next 24h)
    const hourly: HourlyForecast[] = data.hourly.time.slice(0, 24).map((timeStr: string, index: number) => {
      const date = new Date(timeStr);
      const hours = date.getHours().toString().padStart(2, '0');
      const cond = getWeatherCondition(data.hourly.weather_code[index]);

      return {
        time: `${hours}:00`,
        temp: Math.round(data.hourly.temperature_2m[index]),
        precipChance: data.hourly.precipitation_probability[index],
        condition: cond.condition
      };
    });

    // Process Daily Data (next 7 days)
    const daily: DailyForecast[] = data.daily.time.map((timeStr: string, index: number) => {
      // Ensure we parse the date correctly regardless of timezone issues by appending T00:00
      const date = new Date(`${timeStr}T00:00:00`); 
      const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      const cond = getWeatherCondition(data.daily.weather_code[index]);

      return {
        day: days[date.getDay()],
        minTemp: Math.round(data.daily.temperature_2m_min[index]),
        maxTemp: Math.round(data.daily.temperature_2m_max[index]),
        precipChance: data.daily.precipitation_probability_max?.[index] || 0, // Map probability
        condition: cond.condition
      };
    });

    // Generate alerts based on real data conditions
    const alerts: Alert[] = [];
    const code = data.current.weather_code;
    const windSpeed = data.current.wind_speed_10m;
    const precip = data.current.precipitation;
    const temp = data.current.temperature_2m;

    // 1. Storm Alerts (WMO codes for Thunderstorm)
    if ([95, 96, 99].includes(code)) {
      alerts.push({
        id: 'storm-alert',
        severity: 'severe',
        title: 'Thunderstorm Warning',
        description: 'Thunderstorms detected in the area. Seek shelter and avoid open areas.',
        issuedAt: 'Now'
      });
    }

    // 2. Snow/Ice Alerts
    if ([71, 73, 75, 77, 85, 86].includes(code)) {
      alerts.push({
        id: 'snow-alert',
        severity: 'moderate',
        title: 'Snow & Ice Advisory',
        description: 'Snowfall detected. Roads may be slippery. Drive with caution.',
        issuedAt: 'Now'
      });
    }

    // 3. High Wind Alerts (> 40 km/h is breezy, > 60 is dangerous)
    if (windSpeed > 40) {
      alerts.push({
        id: 'wind-alert',
        severity: windSpeed > 60 ? 'severe' : 'moderate',
        title: 'High Wind Warning',
        description: `Current wind speeds are high (${windSpeed} km/h). Secure loose items outside.`,
        issuedAt: 'Now'
      });
    }

    // 4. Heavy Rain (> 5mm/h is roughly heavy)
    if (precip > 5) {
      alerts.push({
        id: 'rain-alert',
        severity: 'moderate',
        title: 'Heavy Rain Detected',
        description: `Significant precipitation (${precip}mm). Visibility may be reduced.`,
        issuedAt: 'Now'
      });
    }

    // 5. Extreme Heat (> 35°C)
    if (temp > 35) {
      alerts.push({
        id: 'heat-alert',
        severity: 'extreme',
        title: 'Excessive Heat Warning',
        description: `Temperatures are very high (${temp}°C). Stay hydrated and avoid direct sun.`,
        issuedAt: 'Now'
      });
    }

    // 6. Freezing Conditions (< 0°C)
    if (temp < 0) {
      alerts.push({
        id: 'freeze-alert',
        severity: 'moderate',
        title: 'Freeze Warning',
        description: `Temperatures are below freezing (${temp}°C). Protect plants and pets.`,
        issuedAt: 'Now'
      });
    }

    // Return formatted data
    return {
      location: {
        city,
        district: district || '',
        lat,
        lng
      },
      current: {
        temp: Math.round(data.current.temperature_2m),
        feelsLike: Math.round(data.current.apparent_temperature),
        humidity: data.current.relative_humidity_2m,
        windSpeed: Math.round(data.current.wind_speed_10m),
        uvIndex: 5, // Note: Basic Open-Meteo doesn't provide UV. Would require extra params/API.
        condition: currentCondition.condition,
        description: currentCondition.description,
        aqi: 30 // Note: AQI requires a separate API call usually.
      },
      hourly,
      daily,
      alerts
    };

  } catch (error) {
    console.error("Error fetching weather data:", error);
    // Re-throw so the UI can handle the error state if needed
    throw error;
  }
};

import React from 'react';
import { DailyForecast } from '../types';
import { Sun, Cloud, CloudRain, CloudLightning, CloudSnow, CloudDrizzle } from 'lucide-react';

interface Props {
  data: DailyForecast[];
}

const AnimatedIcon = ({ condition, precipChance }: { condition: string, precipChance: number }) => {
  // Styles for custom micro-animations
  const styles = `
    @keyframes drop-fall {
      0% { transform: translateY(-5px); opacity: 0; }
      50% { opacity: 1; }
      100% { transform: translateY(5px); opacity: 0; }
    }
    @keyframes snow-drift {
      0% { transform: translate(0, -3px) rotate(0deg); opacity: 0; }
      50% { opacity: 1; }
      100% { transform: translate(-3px, 5px) rotate(180deg); opacity: 0; }
    }
    @keyframes pulse-storm {
      0%, 100% { opacity: 1; filter: drop-shadow(0 0 0 rgba(168, 85, 247, 0)); }
      50% { opacity: 0.8; filter: drop-shadow(0 0 5px rgba(168, 85, 247, 0.5)); }
    }
  `;

  if (condition === 'Storm') {
    return (
      <div className="relative w-8 h-8 flex items-center justify-center">
        <style>{styles}</style>
        <CloudLightning className="w-6 h-6 text-purple-400" style={{ animation: 'pulse-storm 2s infinite' }} />
      </div>
    );
  }

  if (condition === 'Rain' || (condition !== 'Snow' && precipChance > 40)) {
     // Check if it's likely snow based on logic (handled in service), here we assume condition 'Rain' covers general precip
     // but if condition is specifically 'Rain' or high precip chance without being snow:
     const isHeavy = precipChance > 70;
     return (
       <div className="relative w-8 h-8 flex items-center justify-center">
         <style>{styles}</style>
         {isHeavy ? <CloudRain className="w-6 h-6 text-blue-400" /> : <CloudDrizzle className="w-6 h-6 text-blue-300" />}
         {/* Animated Drops */}
         <div className="absolute top-4 left-3 w-0.5 h-1.5 bg-blue-400 rounded-full" style={{ animation: 'drop-fall 1s infinite linear' }}></div>
         <div className="absolute top-4 left-5 w-0.5 h-1.5 bg-blue-400 rounded-full" style={{ animation: 'drop-fall 1s infinite linear', animationDelay: '0.3s' }}></div>
       </div>
     );
  }

  if (condition === 'Snow' || condition.includes('Ice')) {
    return (
      <div className="relative w-8 h-8 flex items-center justify-center">
        <style>{styles}</style>
        <CloudSnow className="w-6 h-6 text-white" />
        <div className="absolute top-4 left-2 w-1 h-1 bg-white rounded-full" style={{ animation: 'snow-drift 2s infinite linear' }}></div>
        <div className="absolute top-3 left-5 w-1 h-1 bg-white rounded-full" style={{ animation: 'snow-drift 2.5s infinite linear', animationDelay: '1s' }}></div>
      </div>
    );
  }

  if (condition === 'Sunny') {
    return <Sun className="w-6 h-6 text-amber-400 animate-[spin_10s_linear_infinite]" />;
  }

  if (condition === 'Partly Cloudy') {
    return <Cloud className="w-6 h-6 text-sky-200" />;
  }

  // Default cloudy
  return <Cloud className="w-6 h-6 text-slate-400" />;
};

