const ConditionIcon = ({ condition }: { condition: string }) => {
  switch (condition) {
    case 'Sunny': return <Sun className="w-16 h-16 text-amber-400" />;
    case 'Rain': return <CloudRain className="w-16 h-16 text-blue-400" />;
    case 'Storm': return <CloudLightning className="w-16 h-16 text-purple-400" />;
    case 'Partly Cloudy': return <Cloud className="w-16 h-16 text-slate-300" />;
    case 'Snow': return <CloudSnow className="w-16 h-16 text-white" />;
