const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.LOADING);
  const [weatherData, setWeatherData] = useState<WeatherData | null>(null);
  const [showMobileMenu, setShowMobileMenu] = useState(false);

  // Search State
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isSearchOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [isSearchOpen]);

  // Function to load weather data using the service
  const loadWeather = async (lat: number, lng: number, locationName: string, district?: string) => {
    try {
      setAppState(AppState.LOADING);
      const data = await fetchWeatherData(lat, lng, locationName, district);
      setWeatherData(data);
      setAppState(AppState.DASHBOARD);
      setIsSearchOpen(false);
      setSearchQuery("");
    } catch (error) {
      console.error("Failed to load weather", error);
      alert("Failed to fetch weather data. Please check your connection.");
      // If we fail and have no data, go back to onboarding
      if (!weatherData) {
        setAppState(AppState.ONBOARDING);
      } else {
        setAppState(AppState.DASHBOARD);
      }
    }
  };

  // Initialize App: Only load if permission granted, otherwise show Search Screen
  useEffect(() => {
    const initApp = async () => {
       if (!navigator.geolocation || !navigator.permissions) {
          setAppState(AppState.ONBOARDING);
          return;
       }

       try {
          // Check if permission is ALREADY granted.
          const permission = await navigator.permissions.query({ name: 'geolocation' as PermissionName });

          if (permission.state === 'granted') {
             navigator.geolocation.getCurrentPosition(
               async (position) => {
                 const { latitude, longitude } = position.coords;

                 // Reverse Geocode Logic
                 let locationName = "Detected Location";
                 let districtName = "";
                 try {
                   const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`);
                   if (response.ok) {
                     const data = await response.json();
                     if (data && data.address) {
                       locationName = data.address.city || data.address.town || data.address.village || "Detected Location";
                       districtName = data.address.suburb || data.address.neighbourhood || "";
                       if (districtName === locationName) districtName = "";
                     }
                   }
                 } catch (e) { /* ignore geocode error */ }

                 loadWeather(latitude, longitude, locationName, districtName);
               },
               (error) => {
                 // Even if granted, if error occurs, go to search screen
                 setAppState(AppState.ONBOARDING);
               }
             );
          } else {
             // If prompt or denied, show the Search Screen (Onboarding)
             setAppState(AppState.ONBOARDING);
           }
       } catch (error) {
          setAppState(AppState.ONBOARDING);
       }
    };

    initApp();
  }, []);

  const handleGrantLocation = () => {
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser.");
      return;
    }

    setAppState(AppState.LOADING);

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        let locationName = "Current Location";
        let districtName = "";

        try {
          const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`);
          if (response.ok) {
            const data = await response.json();
            if (data && data.address) {
              locationName = data.address.city || 
                             data.address.town || 
                             data.address.village || 
                             data.address.municipality ||
                             "Detected Location";

              districtName = data.address.suburb || 
                             data.address.neighbourhood || 
                             data.address.quarter || 
                             "";

              if (districtName === locationName) districtName = "";
            }
