      console.error(error);
      alert("Search failed. Check your connection.");
      setAppState(weatherData ? AppState.DASHBOARD : AppState.ONBOARDING);
    }
  };

  const getSeverityWeight = (severity: string) => {
    if (severity === 'extreme') return 3;
    if (severity === 'severe') return 2;
    return 1;
