import { GoogleGenAI } from "@google/genai";
import { WeatherData } from '../types.ts';

// O Vite injetará isso via 'define' no vite.config.ts
declare var process: {
  env: {
    API_KEY: string;
  };
};

export const generateWeatherInsight = async (data: WeatherData): Promise<string> => {
  try {
    const apiKey = process.env.API_KEY;

    // Fallback: Tentar ler do localStorage se a ENV não estiver definida (útil para dev)
    const storedKey = typeof window !== 'undefined' ? localStorage.getItem('SKYCAST_API_KEY') : null;
    const finalKey = apiKey || storedKey;

    if (!finalKey || finalKey.trim() === "" || finalKey === "undefined") {
      console.warn("API Key missing in environment or localStorage");
      return "AI insights unavailable (Key missing). Please check settings.";
    }

    const ai = new GoogleGenAI({ apiKey: finalKey });

    const locationContext = data.location.city === 'Current Location' 
      ? `Current Location`
      : data.location.city;

    const prompt = `
      Current weather in ${locationContext}:
      ${data.current.condition}, ${data.current.temp}°C.
      Humidity: ${data.current.humidity}%.

      Write a very short, witty 2-sentence weather report. 
      Include a practical clothing tip.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.0-flash-exp', // Usando um modelo rápido e estável
      contents: prompt,
    });

    return response.text || "Enjoy the weather!";

  } catch (error: any) {
    console.error("Gemini Error:", error);
    return "Weather looks interesting today! (AI Offline)";
  }
};

