import React, { useMemo } from 'react';
import { Cloud, CloudRain, CloudSnow, Sun, Zap, Map as MapIcon, Droplets } from 'lucide-react';

interface RadarViewProps {
  condition?: string;
  lat?: number;
  lng?: number;
  precipChance?: number;
}

const RadarView: React.FC<RadarViewProps> = ({ condition = 'Sunny', lat = 0, lng = 0, precipChance = 0 }) => {

  // Determine weather parameters
  const weatherState = useMemo(() => {
    const c = condition.toLowerCase();
    const isStorm = c.includes('storm') || c.includes('thunder');
    const isRain = c.includes('rain') || c.includes('drizzle') || c.includes('shower');
    const isSnow = c.includes('snow') || c.includes('ice') || c.includes('flurry');
    const isCloudy = c.includes('cloud') || c.includes('overcast');
    const isPartly = c.includes('partly');
    const isClear = !isStorm && !isRain && !isSnow && !isCloudy && !isPartly;

    return { isStorm, isRain, isSnow, isCloudy, isPartly, isClear };
  }, [condition]);

  // Generate Cloud Particles (Parallax background)
  const clouds = useMemo(() => {
    if (weatherState.isClear) return [];

    const count = weatherState.isPartly ? 3 : 8;
    // Storm/Rain clouds are darker
    const colorClass = (weatherState.isRain || weatherState.isStorm) ? 'bg-slate-700' : 'bg-slate-300'; 

    return Array.from({ length: count }).map((_, i) => ({
      id: i,
      left: `${Math.random() * 100}%`,
      top: `${Math.random() * 70}%`, 
      size: `${Math.random() * 100 + 80}px`,
      opacity: (weatherState.isRain || weatherState.isStorm) ? 0.6 : 0.4,
      duration: `${Math.random() * 40 + 60}s`, // Slow drift
      delay: `-${Math.random() * 60}s`,
      scale: Math.random() * 0.5 + 1,
      colorClass
    }));
  }, [weatherState]);

  // Generate Precipitation Particles (Rain or Snow)
  const precipitation = useMemo(() => {
    // Storms usually include rain
    const active = weatherState.isRain || weatherState.isSnow || weatherState.isStorm;
    if (!active) return [];

    // More particles for storm/heavy rain
    const count = weatherState.isStorm ? 100 : (weatherState.isSnow ? 50 : 80);

    return Array.from({ length: count }).map((_, i) => ({
      id: i,
      left: `${Math.random() * 100}%`,
      // Rain is fast (0.5-0.9s), Snow is slow (3-6s)
      duration: weatherState.isSnow ? `${Math.random() * 3 + 3}s` : `${Math.random() * 0.4 + 0.5}s`,
      delay: `-${Math.random() * 5}s`,
      opacity: Math.random() * 0.5 + 0.3,
      // Snow is a dot (size), Rain is a streak (height)
      width: weatherState.isSnow ? `${Math.random() * 3 + 2}px` : '1px',
      height: weatherState.isSnow ? `${Math.random() * 3 + 2}px` : `${Math.random() * 15 + 10}px`
    }));
  }, [weatherState]);

  // OpenStreetMap Bounding Box
  const bboxOffset = 0.01;
  const bbox = `${lng - bboxOffset},${lat - bboxOffset},${lng + bboxOffset},${lat + bboxOffset}`;

  return (
    <div className="relative w-full h-72 bg-slate-900 rounded-xl overflow-hidden border border-slate-700 shadow-lg group isolate">

      <style>{`
        /* Slow Horizontal Cloud Drift */
        @keyframes drift {
          0% { transform: translateX(-20px); }
          50% { transform: translateX(20px); }
          100% { transform: translateX(-20px); }
        }

        /* Rain: Fast vertical drop */
        @keyframes rain-fall {
          0% { transform: translateY(-50px) scaleY(1); opacity: 0; }
          20% { opacity: 0.8; }
          90% { opacity: 0.8; }
          100% { transform: translateY(400px) scaleY(1); opacity: 0; }
        }

        /* Snow: Slow fall with horizontal sway */
        @keyframes snow-fall {
          0% { transform: translate(0, -20px); opacity: 0; }
          20% { opacity: 0.9; transform: translate(-5px, 50px); }
          40% { transform: translate(5px, 100px); }
          60% { transform: translate(-10px, 200px); }
          100% { transform: translate(0, 400px); opacity: 0; }
        }

        /* Storm: Sharp flashes */
        @keyframes lightning-flash {
          0%, 92%, 100% { opacity: 0; }
          93%, 97% { opacity: 0.4; background-color: #fff; }
          95% { opacity: 0.1; }
        }
      `}</style>

      {/* 1. Map Layer */}
      <div className="absolute inset-0 z-0 bg-slate-800">
         <iframe 
           width="100%" 
           height="100%" 
           frameBorder="0" 
           scrolling="no" 
           src={`https://www.openstreetmap.org/export/embed.html?bbox=${bbox}&layer=mapnik&marker=${lat},${lng}`}
           style={{ filter: 'grayscale(100%) invert(90%) hue-rotate(180deg) contrast(1.2) brightness(0.7)' }}
           className="w-full h-full pointer-events-none scale-125 origin-center" 
           title="Weather Radar Map"
         ></iframe>
      </div>

      {/* 2. Cloud Layer */}
      <div className="absolute inset-0 z-10 pointer-events-none overflow-hidden">
        {clouds.map((cloud) => (
          <div
            key={cloud.id}
            className={`absolute rounded-full blur-3xl ${cloud.colorClass}`}
            style={{
              left: cloud.left,
              top: cloud.top,
              width: cloud.size,
              height: cloud.size,
              opacity: cloud.opacity,
              animation: `drift ${cloud.duration} ease-in-out infinite`,
              animationDelay: cloud.delay,
            }}
          />
        ))}
      </div>

      {/* 3. Storm Lighting Overlay */}
      {weatherState.isStorm && (
        <div 
          className="absolute inset-0 z-20 pointer-events-none mix-blend-overlay"
          style={{ animation: 'lightning-flash 6s infinite' }}
        />
      )}

      {/* 4. Precipitation Layer (Rain/Snow) */}
      {(weatherState.isRain || weatherState.isSnow || weatherState.isStorm) && (
        <div className="absolute inset-0 z-30 pointer-events-none overflow-hidden">
           {precipitation.map((p) => (
             <div 
               key={p.id}
               className={`absolute ${weatherState.isSnow ? 'bg-white rounded-full blur-[1px]' : 'bg-gradient-to-b from-transparent via-sky-400 to-transparent'}`}
               style={{
                 left: p.left,
                 top: -20,
                 width: p.width,
                 height: p.height,
                 opacity: p.opacity,
                 animation: `${weatherState.isSnow ? 'snow-fall' : 'rain-fall'} ${p.duration} linear infinite`,
                 animationDelay: p.delay,
               }}
             />
           ))}
        </div>
      )}

      {/* 5. UI Overlay / HUD */}
      <div className="absolute inset-0 z-40 p-3 pointer-events-none flex flex-col justify-between">

        {/* Top HUD */}
        <div className="flex justify-between items-start">
           <div className="flex items-center gap-2 text-[10px] font-mono text-slate-300 bg-slate-900/90 px-2 py-1 border border-slate-700 rounded backdrop-blur-sm shadow-lg">
             <MapIcon className="w-3 h-3 text-sky-400" />
             LIVE RADAR
           </div>

           {/* Chance Badge */}
           {(precipChance > 0 || weatherState.isRain || weatherState.isSnow) && (
             <div className="flex items-center gap-2 text-[10px] font-mono text-slate-300 bg-slate-900/90 px-2 py-1 border border-slate-700 rounded backdrop-blur-sm shadow-lg">
               <Droplets className={`w-3 h-3 ${precipChance > 20 ? 'text-blue-400 animate-pulse' : 'text-slate-500'}`} />
               {weatherState.isSnow ? 'SNOW' : 'RAIN'}: <span className="text-white font-bold">{precipChance}%</span>
             </div>
           )}
        </div>

        {/* Bottom HUD */}
        <div className="flex justify-between items-end">
           <div className="text-[9px] font-mono text-slate-500 bg-slate-900/50 p-1 rounded">
             © OSM
           </div>

           <div className="bg-slate-900/90 p-1.5 rounded border border-slate-700 text-slate-300 backdrop-blur-sm shadow-lg">
              {weatherState.isClear && <Sun className="w-4 h-4 text-amber-400 animate-spin-slow" />}
              {(weatherState.isRain || weatherState.isStorm) && <CloudRain className="w-4 h-4 text-blue-400" />}
              {weatherState.isSnow && <CloudSnow className="w-4 h-4 text-white" />}
              {(!weatherState.isClear && !weatherState.isRain && !weatherState.isSnow && !weatherState.isStorm) && <Cloud className="w-4 h-4 text-slate-300" />}
           </div>
        </div>
      </div>

      {/* Center Location Pin */}
      <div className="absolute top-1/2 left-1/2 w-3 h-3 bg-sky-500 rounded-full -translate-x-1/2 -translate-y-1/2 z-30 border-2 border-slate-900 shadow-lg"></div>
      <div className="absolute top-1/2 left-1/2 w-8 h-8 bg-sky-500/30 rounded-full -translate-x-1/2 -translate-y-1/2 z-20 animate-ping"></div>

    </div>
  );
};

export default RadarView;

