import { GoogleGenAI } from "@google/genai";
import { WeatherData } from '../types';

export const generateWeatherInsight = async (data: WeatherData): Promise<string> => {
  try {
    // A chave é injetada via Vite 'define' em process.env.API_KEY
    if (!process.env.API_KEY || process.env.API_KEY === '') {
      console.warn("API_KEY não configurada. Verifique os Secrets do GitHub Actions.");
      return "Dica: Mantenha-se hidratado e aproveite o dia!";
    }

    // Fix: Always use new GoogleGenAI({apiKey: process.env.API_KEY}); as per the SDK guidelines.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const locationContext = data.location.city === 'Current Location' 
      ? `sua localização atual`
      : data.location.city;

    const prompt = `
      Dados meteorológicos atuais em ${locationContext}:
      Condição: ${data.current.condition}, Temperatura: ${data.current.temp}°C.
      Umidade: ${data.current.humidity}%.

      Escreva um relatório meteorológico muito curto e bem-humorado em português (máximo 2 frases).
      Inclua uma dica prática de vestuário.
    `;

    // Fix: Use simple string contents and correct model name according to task type (Basic Text Tasks: gemini-3-flash-preview).
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    // Fix: Access the .text property directly (it is a getter, not a function).
    return response.text || "Aproveite o clima hoje!";

  } catch (error: any) {
    console.error("Erro no Gemini:", error);
    return "O tempo parece interessante hoje! Prepare-se para qualquer mudança.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Navigation, ShieldAlert, LocateFixed, Search, X, Linkedin } from 'lucide-react';
import { WeatherData, AppState } from './types';
import { CITY_COORDINATES } from './constants';
import { fetchWeatherData } from './services/weatherService';
import CurrentConditions from './components/CurrentConditions';
import ForecastChart from './components/ForecastChart';
import RadarView from './components/RadarView';
import AIWeatherInsight from './components/AIWeatherInsight';
import DailyForecastList from './components/DailyForecastList';
import AirQualityPanel from './components/AirQualityPanel';
import WeatherEffects from './components/WeatherEffects';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [weatherData, setWeatherData] = useState<WeatherData | null>(null);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Inicialização do App
  useEffect(() => {
    let isMounted = true;

    const init = async () => {
      // 1. Tentar carregar última preferência
      const savedPreference = localStorage.getItem('skycast_use_location');

      if (savedPreference === 'true') {
        if (isMounted) setAppState(AppState.LOADING);

        navigator.geolocation.getCurrentPosition(
          (pos) => {
            if (isMounted) handleLocationFound(pos.coords.latitude, pos.coords.longitude);
          },
          (err) => {
            console.warn("Auto-location failed, falling back to default city:", err);
            // Se falhar a geolocalização automática, carrega São Paulo por padrão
            if (isMounted) loadDefaultCity();
          },
          { timeout: 5000 }
        );
      } else {
        // Se for a primeira vez, tenta pedir localização, senão carrega padrão após 2 segundos
        const timeoutId = setTimeout(() => {
          if (appState === AppState.ONBOARDING && !weatherData && isMounted) {
            loadDefaultCity();
          }
        }, 3000);

        return () => clearTimeout(timeoutId);
      }
    };

    init();
    return () => { isMounted = false; };
  }, []);

  const loadDefaultCity = () => {
    const defaultCity = "São Paulo";
    const coords = CITY_COORDINATES[defaultCity];
    loadWeather(coords.lat, coords.lng, defaultCity);
  };

  const loadWeather = async (lat: number, lng: number, locationName: string, district?: string) => {
    setAppState(AppState.LOADING);
    try {
      const data = await fetchWeatherData(lat, lng, locationName, district);
      setWeatherData(data);
      setAppState(AppState.DASHBOARD);
      setIsSearchOpen(false);
      setSearchQuery("");
    } catch (error) {
      console.error("Failed to load weather", error);
      // Fallback final: Se tudo falhar, tenta carregar dados mockados
      setAppState(AppState.DASHBOARD); 
    }
  };

  const handleLocationFound = async (latitude: number, longitude: number) => {
    localStorage.setItem('skycast_use_location', 'true');
    let locationName = "Minha Localização";
    let districtName = "";
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`);
      if (response.ok) {
        const data = await response.json();
        if (data && data.address) {
          locationName = data.address.city || data.address.town || data.address.village || "Localização Atual";
          districtName = data.address.suburb || "";
        }
      }
    } catch (e) { 
      console.warn("Reverse geocode failed", e);
    }
    loadWeather(latitude, longitude, locationName, districtName);
  };

  const handleGrantLocation = () => {
    if (!navigator.geolocation) {
      alert("Geolocalização não é suportada pelo seu navegador.");
      loadDefaultCity();
      return;
    }
    setAppState(AppState.LOADING);
    navigator.geolocation.getCurrentPosition(
      (pos) => handleLocationFound(pos.coords.latitude, pos.coords.longitude),
      (err) => {
        console.warn("Location access denied:", err);
        alert("Acesso à localização negado. Carregando cidade padrão.");
        loadDefaultCity();
      },
      { timeout: 10000 }
    );
  };

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    setAppState(AppState.LOADING);
    const normalized = searchQuery.trim().toLowerCase();

    // Verificar se é uma cidade pré-definida
    const predefinedKey = Object.keys(CITY_COORDINATES).find(k => k.toLowerCase() === normalized);
    if (predefinedKey) {
      const { lat, lng } = CITY_COORDINATES[predefinedKey];
      loadWeather(lat, lng, predefinedKey);
      return;
    }

    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(searchQuery)}&limit=1`);
      if (response.ok) {
        const results = await response.json();
        if (results.length > 0) {
          const { lat, lon, name, display_name } = results[0];
          const cityName = name || display_name.split(',')[0];
          loadWeather(parseFloat(lat), parseFloat(lon), cityName);
        } else {
          alert("Cidade não encontrada.");
          setAppState(weatherData ? AppState.DASHBOARD : AppState.ONBOARDING);
        }
      }
    } catch (error) {
      console.error(error);
      alert("Erro na busca. Verifique sua conexão.");
      setAppState(weatherData ? AppState.DASHBOARD : AppState.ONBOARDING);
    }
  };

  if (appState === AppState.LOADING) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center p-4">
        <div className="w-12 h-12 border-4 border-sky-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-slate-400 animate-pulse text-center">Sintonizando satélites...</p>
      </div>
    );
  }

  // Se ainda estiver no Onboarding e sem dados, mostra a tela inicial estilizada
  if (appState === AppState.ONBOARDING && !weatherData) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center p-4 relative overflow-hidden">
        <div className="absolute top-[-20%] left-[-10%] w-[50vw] h-[50vw] bg-sky-500/10 rounded-full blur-[100px] pointer-events-none"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[50vw] h-[50vw] bg-purple-500/10 rounded-full blur-[100px] pointer-events-none"></div>
        <div className="relative z-10 w-full max-w-md text-center space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="flex flex-col items-center gap-4">
            <div className="w-20 h-20 bg-gradient-to-br from-sky-400 to-blue-600 rounded-2xl flex items-center justify-center shadow-2xl shadow-sky-500/20">
