import { GoogleGenAI } from "@google/genai";
import { WeatherData } from '../types';

export const generateWeatherInsight = async (data: WeatherData): Promise<string> => {
  try {
    // Verificação ultra-segura para evitar crash no navegador
    let apiKey = '';

    if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
      apiKey = process.env.API_KEY;
    } else if (typeof window !== 'undefined' && (window as any).VITE_API_KEY) {
      apiKey = (window as any).VITE_API_KEY;
    }

    if (!apiKey || apiKey === '') {
      return "O clima em " + data.location.city + " está variando. Use roupas em camadas para se adaptar!";
    }

    const ai = new GoogleGenAI({ apiKey });
    const locationContext = data.location.city;

    const prompt = `
      Dados meteorológicos atuais em ${locationContext}:
      Condição: ${data.current.condition}, Temperatura: ${data.current.temp}°C.
      Umidade: ${data.current.humidity}%.

      Escreva um relatório meteorológico curto e bem-humorado em português (máximo 2 frases).
      Inclua uma dica prática de vestuário adequada para estas condições.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Aproveite o seu dia com este clima!";

  } catch (error: any) {
    console.warn("Erro ao gerar insight IA:", error);
    return "O tempo em " + data.location.city + " reserva surpresas agradáveis. Prepare-se para aproveitar!";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Navigation, ShieldAlert, LocateFixed, Search, X, Linkedin } from 'lucide-react';
import { WeatherData, AppState } from './types';
import { CITY_COORDINATES } from './constants';
import { fetchWeatherData, getMockData } from './services/weatherService';
import CurrentConditions from './components/CurrentConditions';
import ForecastChart from './components/ForecastChart';
import RadarView from './components/RadarView';
import AIWeatherInsight from './components/AIWeatherInsight';
import DailyForecastList from './components/DailyForecastList';
import AirQualityPanel from './components/AirQualityPanel';
import WeatherEffects from './components/WeatherEffects';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [weatherData, setWeatherData] = useState<WeatherData | null>(null);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Configuração Global: Cidade Padrão é LONDRES
  const DEFAULT_CITY = "London";

  useEffect(() => {
    let isMounted = true;

    // Timer de segurança: Se em 5 segundos nada carregar, força Londres
    const emergencyTimer = setTimeout(() => {
      if (isMounted && appState === AppState.LOADING && !weatherData) {
        console.warn("Emergency load triggered: Initialization took too long.");
        loadDefaultCity();
      }
    }, 5000);

    const init = async () => {
      const savedPreference = localStorage.getItem('skycast_use_location');

      if (savedPreference === 'true') {
        if (isMounted) setAppState(AppState.LOADING);
        navigator.geolocation.getCurrentPosition(
          (pos) => {
            if (isMounted) handleLocationFound(pos.coords.latitude, pos.coords.longitude);
          },
          () => {
            if (isMounted) loadDefaultCity();
          },
          { timeout: 3000 } // Desiste rápido da localização se demorar
        );
      } else {
        // Primeira vez: tenta localizar por 2 segundos, se não, carrega Londres
        const timer = setTimeout(() => {
          if (isMounted && !weatherData) loadDefaultCity();
        }, 2000);
        return () => clearTimeout(timer);
      }
    };

    init();
    return () => { 
      isMounted = false;
      clearTimeout(emergencyTimer);
    };
  }, []);

  const loadDefaultCity = () => {
    const coords = CITY_COORDINATES[DEFAULT_CITY];
    loadWeather(coords.lat, coords.lng, DEFAULT_CITY);
  };

  const loadWeather = async (lat: number, lng: number, locationName: string, district?: string) => {
    setAppState(AppState.LOADING);
    try {
      const data = await fetchWeatherData(lat, lng, locationName, district);
      setWeatherData(data);
      setAppState(AppState.DASHBOARD);
      setIsSearchOpen(false);
    } catch (error) {
      console.error("Load weather failed, using fallback data", error);
      // Garante que o app saia da "tela azul" mesmo em erro total
      setWeatherData(getMockData(locationName));
      setAppState(AppState.DASHBOARD);
    }
  };

  const handleLocationFound = async (latitude: number, longitude: number) => {
    localStorage.setItem('skycast_use_location', 'true');
    let locationName = "Current Location";
    try {
      // Timeout curto para o reverse geocode
      const controller = new AbortController();
      const id = setTimeout(() => controller.abort(), 2000);

      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`,
        { signal: controller.signal }
      );
      clearTimeout(id);

      if (response.ok) {
        const data = await response.json();
        locationName = data.address.city || data.address.town || data.address.village || "My Location";
      }
    } catch (e) { 
      console.warn("Reverse geocode failed, using coordinates name");
    }
    loadWeather(latitude, longitude, locationName);
  };

  const handleGrantLocation = () => {
    if (!navigator.geolocation) {
      loadDefaultCity();
      return;
    }
    setAppState(AppState.LOADING);
    navigator.geolocation.getCurrentPosition(
      (pos) => handleLocationFound(pos.coords.latitude, pos.coords.longitude),
      () => {
        alert("Location access denied. Loading London instead.");
        loadDefaultCity();
      },
      { timeout: 5000 }
    );
  };

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    const normalized = searchQuery.trim();

    // Busca rápida em constantes
    const predefined = Object.keys(CITY_COORDINATES).find(k => k.toLowerCase() === normalized.toLowerCase());
    if (predefined) {
      loadWeather(CITY_COORDINATES[predefined].lat, CITY_COORDINATES[predefined].lng, predefined);
      return;
    }

    setAppState(AppState.LOADING);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(normalized)}&limit=1`);
      const results = await response.json();
      if (results.length > 0) {
        loadWeather(parseFloat(results[0].lat), parseFloat(results[0].lon), results[0].name);
      } else {
        alert("City not found.");
        setAppState(weatherData ? AppState.DASHBOARD : AppState.ONBOARDING);
      }
    } catch (error) {
      setAppState(weatherData ? AppState.DASHBOARD : AppState.ONBOARDING);
    }
  };

  if (appState === AppState.LOADING && !weatherData) {
    return (
      <div className="min-h-screen bg-[#0f172a] flex flex-col items-center justify-center p-4">
        <div className="w-16 h-16 border-4 border-sky-500 border-t-transparent rounded-full animate-spin mb-6 shadow-[0_0_20px_rgba(14,165,233,0.3)]"></div>
        <p className="text-sky-400 animate-pulse font-medium text-lg">SkyCast AI is connecting...</p>
        <button 
          onClick={loadDefaultCity}
          className="mt-8 text-slate-500 text-sm hover:text-sky-400 underline transition-colors"
        >
          Skip to London
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-50 relative overflow-x-hidden selection:bg-sky-500/30">
      {weatherData && <WeatherEffects condition={weatherData.current.condition} />}

      <header className="fixed top-0 w-full bg-[#0f172a]/80 backdrop-blur-md border-b border-slate-800/50 z-50 px-4 py-3 flex items-center justify-between">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setAppState(AppState.ONBOARDING)}>
          <div className="w-8 h-8 bg-sky-500 rounded-lg flex items-center justify-center shadow-lg shadow-sky-500/20">
             <Navigation className="w-5 h-5 text-white" />
          </div>
          <span className="font-bold text-lg hidden sm:block tracking-tight">SkyCast AI</span>
        </div>

        <div className="flex items-center gap-2">
          {isSearchOpen ? (
            <form onSubmit={handleSearchSubmit} className="flex relative">
              <input 
                ref={searchInputRef}
                type="text" 
                autoFocus
                className="bg-slate-800/50 border border-sky-500/50 text-white text-sm rounded-lg pl-3 pr-8 py-2 outline-none w-40 sm:w-64 focus:ring-2 ring-sky-500/20 transition-all"
                placeholder="Search city..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button type="button" onClick={() => setIsSearchOpen(false)} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white"><X className="w-4 h-4" /></button>
            </form>
          ) : (
            <button onClick={() => setIsSearchOpen(true)} className="bg-slate-800/50 hover:bg-slate-700 p-2 rounded-lg transition-colors border border-slate-700/50"><Search className="w-5 h-5 text-slate-300" /></button>
          )}
          <button onClick={handleGrantLocation} className="bg-slate-800/50 hover:bg-slate-700 p-2 rounded-lg text-sky-400 transition-colors border border-slate-700/50"><LocateFixed className="w-5 h-5" /></button>
        </div>
      </header>

      <main className="container mx-auto px-4 pt-20 pb-10 max-w-5xl relative z-10">
        {weatherData ? (
          <>
            {weatherData.alerts.length > 0 && (
              <div className="mb-6 space-y-3">
                {weatherData.alerts.map(alert => (
                  <div key={alert.id} className="bg-red-900/20 border border-red-500/30 rounded-xl p-4 flex gap-4 items-center animate-in slide-in-from-top duration-500 backdrop-blur-md">
                    <ShieldAlert className="w-6 h-6 text-red-500 shrink-0" />
                    <div>
                      <h3 className="font-bold text-red-200">{alert.title}</h3>
                      <p className="text-sm text-red-300/80">{alert.description}</p>
                    </div>
                  </div>
                ))}
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="md:col-span-2 space-y-6">
                <CurrentConditions data={weatherData} />
                <div className="bg-slate-800/30 border border-slate-700/30 rounded-2xl p-6 backdrop-blur-sm shadow-xl">
                  <h3 className="font-semibold text-slate-200 mb-6 flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-sky-500 rounded-full animate-pulse"></div>
                    Hourly Forecast
