import React, { useState, useRef, useEffect } from 'react';
import { Navigation, ShieldAlert, LocateFixed, Search, X, Linkedin, MapPin } from 'lucide-react';
import { WeatherData, AppState } from './types';
import { CITY_COORDINATES } from './constants';
import { fetchWeatherData, getMockData } from './services/weatherService';
import CurrentConditions from './components/CurrentConditions';
import ForecastChart from './components/ForecastChart';
import RadarView from './components/RadarView';
import AIWeatherInsight from './components/AIWeatherInsight';
import DailyForecastList from './components/DailyForecastList';
import AirQualityPanel from './components/AirQualityPanel';
import WeatherEffects from './components/WeatherEffects';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.LOADING);
  const [weatherData, setWeatherData] = useState<WeatherData | null>(null);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [isLocating, setIsLocating] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  const DEFAULT_CITY = "London";

  useEffect(() => {
    let isMounted = true;

    const initializeApp = async () => {
      if (!isMounted) return;

      const getPosition = () => {
        return new Promise<GeolocationPosition>((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject, {
            enableHighAccuracy: false,
            timeout: 4000,
            maximumAge: 60000
          });
        });
      };

      try {
        setIsLocating(true);
        const position = await getPosition();
        if (isMounted) {
          await handleLocationFound(position.coords.latitude, position.coords.longitude);
        }
      } catch (error) {
        console.warn("Location priority failed, falling back to London.", error);
        if (isMounted) loadDefaultCity();
      } finally {
        if (isMounted) setIsLocating(false);
      }
    };

    initializeApp();
    return () => { isMounted = false; };
  }, []);

  const loadDefaultCity = () => {
    const coords = CITY_COORDINATES[DEFAULT_CITY];
    loadWeather(coords.lat, coords.lng, DEFAULT_CITY);
  };

  const loadWeather = async (lat: number, lng: number, locationName: string, district?: string) => {
    try {
      const data = await fetchWeatherData(lat, lng, locationName, district);
      // Pequeno delay para garantir que a animação de loading seja vista e a transição seja suave
      setTimeout(() => {
        setWeatherData(data);
        setAppState(AppState.DASHBOARD);
        setIsSearchOpen(false);
      }, 600);
    } catch (error) {
      setWeatherData(getMockData(locationName));
      setAppState(AppState.DASHBOARD);
    }
  };

  const handleLocationFound = async (latitude: number, longitude: number) => {
    let locationName = "Current Location";
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`,
        { signal: AbortSignal.timeout(3000) }
      );
      if (response.ok) {
        const data = await response.json();
        locationName = data.address.city || data.address.town || data.address.village || "My Location";
      }
    } catch (e) { console.warn("Naming service unavailable"); }
    await loadWeather(latitude, longitude, locationName);
  };

  const handleManualLocationRequest = () => {
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => handleLocationFound(pos.coords.latitude, pos.coords.longitude).finally(() => setIsLocating(false)),
      () => {
        setIsLocating(false);
        loadDefaultCity();
      }
    );
  };

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    const normalized = searchQuery.trim();

    const predefined = Object.keys(CITY_COORDINATES).find(k => k.toLowerCase() === normalized.toLowerCase());
    if (predefined) {
      loadWeather(CITY_COORDINATES[predefined].lat, CITY_COORDINATES[predefined].lng, predefined);
      return;
    }

    setAppState(AppState.LOADING);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(normalized)}&limit=1`);
      const results = await response.json();
      if (results.length > 0) {
        loadWeather(parseFloat(results[0].lat), parseFloat(results[0].lon), results[0].name);
      } else {
        setAppState(AppState.DASHBOARD);
      }
    } catch (error) {
      setAppState(AppState.DASHBOARD);
    }
  };

  if (appState === AppState.LOADING) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 overflow-hidden">
        <style>{`
          @keyframes aurora {
            0% { transform: translate(-20%, -20%) rotate(0deg); }
            50% { transform: translate(20%, 20%) rotate(180deg); }
            100% { transform: translate(-20%, -20%) rotate(360deg); }
          }
        `}</style>

        {/* Animated Background for Loading */}
        <div className="absolute inset-0 opacity-30 pointer-events-none">
          <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] bg-[radial-gradient(circle_at_center,_#0ea5e9_0%,_transparent_40%)] animate-[aurora_20s_linear_infinite]"></div>
          <div className="absolute bottom-[-50%] right-[-50%] w-[200%] h-[200%] bg-[radial-gradient(circle_at_center,_#6366f1_0%,_transparent_40%)] animate-[aurora_15s_linear_infinite_reverse]"></div>
        </div>

        <div className="relative z-10 flex flex-col items-center">
          <div className="w-24 h-24 mb-10 relative">
             <div className="absolute inset-0 bg-sky-500 rounded-3xl rotate-12 animate-pulse opacity-20"></div>
             <div className="absolute inset-0 bg-sky-500 rounded-3xl -rotate-6 animate-pulse opacity-20 delay-700"></div>
             <div className="relative bg-slate-900 border border-slate-800 w-full h-full rounded-3xl flex items-center justify-center shadow-2xl">
                <Navigation className="w-10 h-10 text-sky-400 animate-bounce" />
             </div>
          </div>

          <h1 className="text-2xl font-bold text-white tracking-widest uppercase mb-2">SkyCast AI</h1>
          <div className="flex items-center gap-3 text-slate-400 font-medium">
            <MapPin className="w-4 h-4 text-sky-500 animate-pulse" />
            <span className="text-sm tracking-wide">Buscando sua localização...</span>
          </div>

          <div className="mt-12 flex gap-4">
             <div className="w-1.5 h-1.5 rounded-full bg-sky-500 animate-bounce"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-sky-500 animate-bounce [animation-delay:0.2s]"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-sky-500 animate-bounce [animation-delay:0.4s]"></div>
          </div>

          <button 
            onClick={loadDefaultCity}
            className="mt-20 text-xs text-slate-500 hover:text-sky-400 transition-colors uppercase tracking-[0.2em] border-b border-transparent hover:border-sky-500/50 pb-1"
          >
            Pular para Londres
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-50 relative overflow-x-hidden selection:bg-sky-500/30">
      {weatherData && <WeatherEffects condition={weatherData.current.condition} />}

      <header className="fixed top-0 w-full bg-[#020617]/60 backdrop-blur-xl border-b border-slate-800/50 z-50 px-6 py-4 flex items-center justify-between transition-all duration-500">
        <div className="flex items-center gap-3 cursor-pointer group" onClick={() => window.location.reload()}>
          <div className="w-10 h-10 bg-gradient-to-br from-sky-500 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-sky-500/20 group-hover:scale-105 transition-transform duration-300">
             <Navigation className="w-5 h-5 text-white" />
          </div>
          <span className="font-bold text-xl tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">SkyCast AI</span>
        </div>

        <div className="flex items-center gap-3">
          {isSearchOpen ? (
            <form onSubmit={handleSearchSubmit} className="flex relative animate-in fade-in zoom-in-95 duration-300">
              <input 
                ref={searchInputRef}
                type="text" 
                autoFocus
                className="bg-slate-900/80 border border-sky-500/30 text-white text-sm rounded-xl pl-4 pr-10 py-2.5 outline-none w-48 sm:w-72 focus:ring-2 ring-sky-500/20 transition-all backdrop-blur-md"
                placeholder="Qual cidade deseja ver?"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button type="button" onClick={() => setIsSearchOpen(false)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white transition-colors"><X className="w-4 h-4" /></button>
            </form>
          ) : (
            <button onClick={() => setIsSearchOpen(true)} className="bg-slate-900/50 hover:bg-slate-800 p-2.5 rounded-xl transition-all border border-slate-800 hover:border-slate-700"><Search className="w-5 h-5 text-slate-300" /></button>
          )}
          <button 
            onClick={handleManualLocationRequest} 
            disabled={isLocating}
            className={`bg-slate-900/50 hover:bg-slate-800 p-2.5 rounded-xl transition-all border border-slate-800 hover:border-slate-700 relative overflow-hidden group ${isLocating ? 'cursor-not-allowed opacity-50' : ''}`}
          >
            <LocateFixed className={`w-5 h-5 text-sky-400 ${isLocating ? 'animate-spin' : 'group-hover:scale-110 transition-transform'}`} />
            {isLocating && <div className="absolute inset-0 bg-sky-500/10 animate-pulse"></div>}
          </button>
        </div>
      </header>

      <main className="container mx-auto px-4 pt-24 pb-12 max-w-6xl relative z-10">
        {weatherData && (
          <div className="grid grid-cols-1 md:grid-cols-12 gap-6">

            {/* Left Column: Alerts & Current */}
            <div className="md:col-span-8 space-y-6">
              {weatherData.alerts.length > 0 && (
                <div className="space-y-3 animate-in slide-in-from-top-4 duration-700">
                  {weatherData.alerts.map(alert => (
                    <div key={alert.id} className="bg-red-500/10 border border-red-500/20 rounded-3xl p-5 flex gap-5 items-center backdrop-blur-xl group">
                      <div className="w-12 h-12 rounded-2xl bg-red-500/20 flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform">
                        <ShieldAlert className="w-6 h-6 text-red-500" />
                      </div>
                      <div>
                        <h3 className="font-bold text-red-100 uppercase text-xs tracking-widest mb-1">Alerta de Risco</h3>
                        <p className="text-sm text-red-200/80 font-medium">{alert.description}</p>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              <div className="animate-in fade-in slide-in-from-bottom-8 duration-700">
                <CurrentConditions data={weatherData} />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="bg-slate-900/40 border border-slate-800/50 rounded-[2.5rem] p-8 backdrop-blur-md shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-700 delay-150">
                  <h3 className="font-bold text-slate-100 mb-8 flex items-center gap-3">
                    <div className="w-2 h-2 bg-sky-500 rounded-full"></div>
                    Fluxo Térmico 12h
                  </h3>
                  <ForecastChart data={weatherData.hourly} />
                </div>

                <div className="bg-slate-900/40 border border-slate-800/50 rounded-[2.5rem] p-1 overflow-hidden backdrop-blur-md shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-700 delay-200">
                  <RadarView condition={weatherData.current.condition} lat={weatherData.location.lat} lng={weatherData.location.lng} precipChance={weatherData.hourly[0]?.precipChance || 0} />
                </div>
              </div>
            </div>

            {/* Right Column: AI & Stats */}
            <div className="md:col-span-4 space-y-6">
              <div className="animate-in fade-in slide-in-from-right-8 duration-700 delay-100">
