import React, { useState, useRef, useEffect } from 'react';
import { Navigation, ShieldAlert, LocateFixed, Search, X, Linkedin, MapPin } from 'lucide-react';
import { WeatherData, AppState } from './types';
import { CITY_COORDINATES } from './constants';
import { fetchWeatherData, getMockData } from './services/weatherService';
import { t, getLocale } from './utils/i18n';
import CurrentConditions from './components/CurrentConditions';
import ForecastChart from './components/ForecastChart';
import RadarView from './components/RadarView';
import AIWeatherInsight from './components/AIWeatherInsight';
import DailyForecastList from './components/DailyForecastList';
import AirQualityPanel from './components/AirQualityPanel';
import WeatherEffects from './components/WeatherEffects';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.LOADING);
  const [weatherData, setWeatherData] = useState<WeatherData | null>(null);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [isLocating, setIsLocating] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);
  const trans = t();
  const locale = getLocale();

  const DEFAULT_CITY = "London";

  useEffect(() => {
    let isMounted = true;
    const initializeApp = async () => {
      const getPosition = () => {
        return new Promise<GeolocationPosition>((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject, {
            enableHighAccuracy: false,
            timeout: 4000,
            maximumAge: 60000
          });
        });
      };

      try {
        setIsLocating(true);
        const position = await getPosition();
        if (isMounted) await handleLocationFound(position.coords.latitude, position.coords.longitude);
      } catch (error) {
        if (isMounted) loadDefaultCity();
      } finally {
        if (isMounted) setIsLocating(false);
      }
    };

    initializeApp();
    return () => { isMounted = false; };
  }, []);

  const loadDefaultCity = () => {
    const coords = CITY_COORDINATES[DEFAULT_CITY];
    loadWeather(coords.lat, coords.lng, DEFAULT_CITY);
  };

  const loadWeather = async (lat: number, lng: number, locationName: string, district?: string) => {
    try {
      const data = await fetchWeatherData(lat, lng, locationName, district);
      setTimeout(() => {
        setWeatherData(data);
        setAppState(AppState.DASHBOARD);
        setIsSearchOpen(false);
      }, 600);
    } catch (error) {
      setWeatherData(getMockData(locationName));
      setAppState(AppState.DASHBOARD);
    }
  };

  const handleLocationFound = async (latitude: number, longitude: number) => {
    let locationName = locale === 'pt' ? "Minha Localização" : "My Location";
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&accept-language=${locale}`,
        { signal: AbortSignal.timeout(3000) }
      );
      if (response.ok) {
        const data = await response.json();
        locationName = data.address.city || data.address.town || data.address.village || locationName;
      }
    } catch (e) {}
    await loadWeather(latitude, longitude, locationName);
  };

  const handleManualLocationRequest = () => {
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => handleLocationFound(pos.coords.latitude, pos.coords.longitude).finally(() => setIsLocating(false)),
      () => {
        setIsLocating(false);
        loadDefaultCity();
      }
    );
  };

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    const normalized = searchQuery.trim();

    const predefined = Object.keys(CITY_COORDINATES).find(k => k.toLowerCase() === normalized.toLowerCase());
    if (predefined) {
      loadWeather(CITY_COORDINATES[predefined].lat, CITY_COORDINATES[predefined].lng, predefined);
      return;
    }

    setAppState(AppState.LOADING);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(normalized)}&limit=1&accept-language=${locale}`);
      const results = await response.json();
      if (results.length > 0) {
        loadWeather(parseFloat(results[0].lat), parseFloat(results[0].lon), results[0].name);
      } else {
        setAppState(AppState.DASHBOARD);
      }
    } catch (error) {
      setAppState(AppState.DASHBOARD);
    }
  };

  if (appState === AppState.LOADING) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6">
        <div className="relative z-10 flex flex-col items-center">
          <div className="w-24 h-24 mb-10 relative">
             <div className="absolute inset-0 bg-sky-500 rounded-3xl rotate-12 animate-pulse opacity-20"></div>
             <div className="relative bg-slate-900 border border-slate-800 w-full h-full rounded-3xl flex items-center justify-center shadow-2xl">
                <Navigation className="w-10 h-10 text-sky-400 animate-bounce" />
             </div>
          </div>
          <h1 className="text-2xl font-bold text-white tracking-widest uppercase mb-2">SkyCast AI</h1>
          <div className="flex items-center gap-3 text-slate-400 font-medium text-center">
            <MapPin className="w-4 h-4 text-sky-500 animate-pulse shrink-0" />
            <span className="text-sm tracking-wide">{trans.loadingSub}</span>
          </div>
          <button onClick={loadDefaultCity} className="mt-20 text-xs text-slate-500 hover:text-sky-400 uppercase tracking-[0.2em]">{trans.skipToLondon}</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-50 relative overflow-x-hidden">
      {weatherData && <WeatherEffects condition={weatherData.current.condition} />}
      <header className="fixed top-0 w-full bg-[#020617]/60 backdrop-blur-xl border-b border-slate-800/50 z-50 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-3 cursor-pointer group" onClick={() => window.location.reload()}>
          <div className="w-10 h-10 bg-gradient-to-br from-sky-500 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg">
             <Navigation className="w-5 h-5 text-white" />
          </div>
          <span className="font-bold text-xl tracking-tight">SkyCast AI</span>
        </div>
        <div className="flex items-center gap-3">
          {isSearchOpen ? (
            <form onSubmit={handleSearchSubmit} className="flex relative animate-in fade-in zoom-in-95">
              <input 
                ref={searchInputRef}
                type="text" 
                autoFocus
                className="bg-slate-900/80 border border-sky-500/30 text-white text-sm rounded-xl pl-4 pr-10 py-2.5 outline-none w-48 sm:w-72"
                placeholder={trans.searchPlaceholder}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <button type="button" onClick={() => setIsSearchOpen(false)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400"><X className="w-4 h-4" /></button>
            </form>
          ) : (
            <button onClick={() => setIsSearchOpen(true)} className="bg-slate-900/50 hover:bg-slate-800 p-2.5 rounded-xl border border-slate-800"><Search className="w-5 h-5 text-slate-300" /></button>
          )}
          <button onClick={handleManualLocationRequest} disabled={isLocating} className="bg-slate-900/50 hover:bg-slate-800 p-2.5 rounded-xl border border-slate-800">
            <LocateFixed className={`w-5 h-5 text-sky-400 ${isLocating ? 'animate-spin' : ''}`} />
          </button>
        </div>
      </header>

      <main className="container mx-auto px-4 pt-24 pb-12 max-w-6xl relative z-10">
        {weatherData && (
          <div className="grid grid-cols-1 md:grid-cols-12 gap-6">
            <div className="md:col-span-8 space-y-6">
              {weatherData.alerts.length > 0 && (
                <div className="space-y-3">
                  {weatherData.alerts.map(alert => (
                    <div key={alert.id} className="bg-red-500/10 border border-red-500/20 rounded-3xl p-5 flex gap-5 items-center">
                      <ShieldAlert className="w-6 h-6 text-red-500" />
                      <div>
                        <h3 className="font-bold text-red-100 uppercase text-xs tracking-widest">{trans.riskAlert}</h3>
                        <p className="text-sm text-red-200/80">{alert.description}</p>
                      </div>
                    </div>
                  ))}
                </div>
              )}
              <CurrentConditions data={weatherData} />
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="bg-slate-900/40 border border-slate-800/50 rounded-[2.5rem] p-8 backdrop-blur-md shadow-2xl">
                  <h3 className="font-bold text-slate-100 mb-8 flex items-center gap-3 text-sm uppercase tracking-widest opacity-70">
                    {trans.thermalFlow}
                  </h3>
                  <ForecastChart data={weatherData.hourly} />
                </div>
                <div className="bg-slate-900/40 border border-slate-800/50 rounded-[2.5rem] p-1 overflow-hidden backdrop-blur-md shadow-2xl">
                  <RadarView condition={weatherData.current.condition} lat={weatherData.location.lat} lng={weatherData.location.lng} precipChance={weatherData.hourly[0]?.precipChance || 0} />
                </div>
              </div>
            </div>
            <div className="md:col-span-4 space-y-6">
              <AIWeatherInsight weatherData={weatherData} />
              <AirQualityPanel data={weatherData.current} />
              <div className="bg-slate-900/40 border border-slate-800/50 rounded-[2.5rem] p-8 backdrop-blur-md shadow-2xl">
                <h3 className="font-bold text-slate-100 mb-6">{trans.nextDays}</h3>
                <DailyForecastList data={weatherData.daily} />
              </div>
