           width="100%" 
           height="100%" 
           frameBorder="0" 
           src={`https://www.openstreetmap.org/export/embed.html?bbox=${bbox}&layer=mapnik&marker=${lat},${lng}`}
           style={{ animation: 'map-focus 2s cubic-bezier(0.16, 1, 0.3, 1) forwards' }}
           className="w-full h-full pointer-events-none origin-center"
         ></iframe>
         {/* Dark Overlay for better contrast */}
         <div className="absolute inset-0 bg-slate-900/10 pointer-events-none"></div>
      </div>

      {/* Radar UI Overlays */}
      <div className="absolute inset-0 z-40 p-5 pointer-events-none flex flex-col justify-between">
        <div className="flex justify-between items-start">
           <div className="flex items-center gap-2 text-[10px] font-bold text-sky-400 bg-slate-950/80 px-4 py-2 border border-sky-500/20 rounded-xl backdrop-blur-xl shadow-lg">
