             {trans.precipChance} {weatherState.isSnow ? trans.snow : trans.rain}: 
             <span className="text-white font-black ml-1">{precipChance}%</span>
           </div>
        </div>

        <div className="flex justify-center mb-2">
           <div className="bg-slate-950/80 px-4 py-1.5 rounded-full border border-slate-800/50 backdrop-blur-md flex items-center gap-2">
              <MapIcon className="w-3 h-3 text-slate-500" />
              <span className="text-[9px] text-slate-400 font-bold tracking-tighter uppercase">
                {dynamicBboxOffset < 0.003 ? 'Precision Mode' : 'Standard View'}: {lat.toFixed(4)}, {lng.toFixed(4)}
              </span>
           </div>
        </div>
      </div>

      {/* High-Precision Marker with Triple Pulse */}
      <div className="absolute top-1/2 left-1/2 z-30">
