import React, { useMemo } from 'react';
import { Target } from 'lucide-react';
import { t } from '../utils/i18n';

interface RadarViewProps {
  condition?: string;
  lat?: number;
  lng?: number;
  precipChance?: number;
}

const RadarView: React.FC<RadarViewProps> = ({ condition = 'Sunny', lat = 0, lng = 0, precipChance = 0 }) => {
  const trans = t();

  const weatherState = useMemo(() => {
    const c = condition.toLowerCase();
    const isStorm = c.includes('storm') || c.includes('thunder');
    const isRain = c.includes('rain') || c.includes('drizzle') || c.includes('shower');
    const isSnow = c.includes('snow') || c.includes('ice') || c.includes('flurry');
    return { isStorm, isRain, isSnow };
  }, [condition]);

  // Zoom Dinâmico: Menor offset = Mais Zoom.
  const dynamicBboxOffset = useMemo(() => {
    // Eventos extremos: Zoom nível de rua
    if (weatherState.isStorm || precipChance > 80) return 0.002;
    // Eventos moderados: Zoom nível de bairro
    if (weatherState.isRain || weatherState.isSnow || precipChance > 40) return 0.005;
    // Padrão: Visão distrital
    return 0.01;
  }, [weatherState, precipChance]);

  const bbox = `${lng - dynamicBboxOffset},${lat - (dynamicBboxOffset / 2)},${lng + dynamicBboxOffset},${lat + (dynamicBboxOffset / 2)}`;

  return (
    <div className="relative w-full h-80 bg-[#020617] rounded-[2.5rem] overflow-hidden border border-slate-800/50 group isolate shadow-2xl">
      <style>{`
        @keyframes map-focus {
          0% { transform: scale(1.4); filter: blur(4px) grayscale(1); }
          100% { transform: scale(1.1); filter: blur(0) grayscale(1) invert(0.9) hue-rotate(180deg) contrast(1.1); }
        }
        @keyframes radar-sweep {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
        @keyframes radar-pulse {
          0% { transform: translate(-50%, -50%) scale(1); opacity: 0.6; }
          100% { transform: translate(-50%, -50%) scale(4); opacity: 0; }
        }
      `}</style>

      {/* Map Layer */}
      <div className="absolute inset-0 z-0">
         <iframe 
           key={`${lat}-${lng}-${dynamicBboxOffset}`} // Força recarregamento ao mudar o zoom
           width="100%" 
           height="100%" 
           frameBorder="0" 
           src={`https://www.openstreetmap.org/export/embed.html?bbox=${bbox}&layer=mapnik&marker=${lat},${lng}`}
           style={{ animation: 'map-focus 1.5s cubic-bezier(0.2, 1, 0.3, 1) forwards' }}
           className="w-full h-full pointer-events-none origin-center"
         ></iframe>
      </div>

      {/* Interface Overlays (Minimal) */}
      <div className="absolute inset-0 z-40 p-5 pointer-events-none flex flex-col justify-between">
        <div className="flex justify-between items-start">
           <div className="flex items-center gap-2 text-[10px] font-bold text-sky-400 bg-slate-950/90 px-3 py-1.5 border border-sky-500/20 rounded-lg backdrop-blur-xl">
             <div className="w-1.5 h-1.5 bg-sky-500 rounded-full animate-pulse"></div>
             {trans.liveRadar}
           </div>

           <div className="flex items-center gap-2 text-[10px] font-bold text-slate-300 bg-slate-950/90 px-3 py-1.5 border border-slate-800/50 rounded-lg backdrop-blur-xl">
             {trans.precipChance} {weatherState.isSnow ? trans.snow : trans.rain}: <span className="text-white ml-1">{precipChance}%</span>
           </div>
        </div>
      </div>

      {/* Center Marker */}
